"use client"

import { useState, useTransition, useRef } from "react"
import { useLocale, useTranslations } from "next-intl"
import { toast } from "sonner"
import { Mail, CheckCircle2 } from "lucide-react"
import { 
  Card, 
  CardHeader, 
  CardTitle, 
  CardDescription, 
  CardContent, 
  CardFooter 
} from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { requestEmailChange } from "@/lib/settings-actions"

type EmailFormProps = {
  initialEmail: string
}

export function EmailForm({ initialEmail }: EmailFormProps) {
  const t = useTranslations("settings.email")
  const locale = useLocale()
  const [isPending, startTransition] = useTransition()
  const [successSent, setSuccessSent] = useState(false)
  const formRef = useRef<HTMLFormElement>(null)

  async function handleSubmit(formData: FormData) {
    const email = formData.get("email") as string
    
    // We remove the strict client-side verification of email === initialEmail
    // because after the update, `initialEmail` comes from page.tsx passing the new DB data
    // while the client form state might sometimes lag or re-render unpredictably.
    // Let the Server Action `requestEmailChange` handle that logic securely.

    startTransition(async () => {
      const result = await requestEmailChange(formData)
      if (result.success) {
        setSuccessSent(true)
        toast.success(t("success"))
        if (typeof navigator !== "undefined" && navigator.vibrate) navigator.vibrate(50)
      } else {
        toast.error(result.error || t("error"))
      }
    })
  }

  return (
    <Card className="border-indigo-500/20 dark:border-indigo-500/10 bg-white/50 dark:bg-zinc-900/50 backdrop-blur-sm">
      <CardHeader>
        <div className="flex items-center gap-2">
          <Mail className="h-5 w-5 text-indigo-500 dark:text-indigo-400" />
          <CardTitle className="text-indigo-600 dark:text-indigo-400">{t("title")}</CardTitle>
        </div>
        <CardDescription>{t("subtitle")}</CardDescription>
      </CardHeader>
      
      {successSent ? (
        <CardContent className="space-y-4 pt-4">
          <div className="rounded-lg bg-emerald-50 dark:bg-emerald-500/10 px-4 py-4 border border-emerald-100 dark:border-emerald-500/20 flex flex-col items-center text-center space-y-3">
             <CheckCircle2 className="h-10 w-10 text-emerald-500" />
             <p className="text-sm text-emerald-700 dark:text-emerald-400 font-medium">
               {t("checkEmail")}
             </p>
             <Button variant="outline" onClick={() => setSuccessSent(false)} className="mt-2 text-xs">
                Close
             </Button>
          </div>
        </CardContent>
      ) : (
        <form ref={formRef} action={handleSubmit}>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="currentEmail">{t("current")}</Label>
              <Input 
                id="currentEmail" 
                value={initialEmail}
                readOnly
                disabled
                className="bg-zinc-100 dark:bg-zinc-800 text-zinc-500 opacity-70"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="email">{t("new")}</Label>
              <Input 
                id="email" 
                name="email" 
                type="email"
                required 
                placeholder="new@example.com"
                className="bg-zinc-50 dark:bg-zinc-800/50"
              />
            </div>
            <input type="hidden" name="locale" value={locale} />
          </CardContent>
          <CardFooter className="border-t border-indigo-500/10 dark:border-indigo-500/5 px-6 py-4">
            <Button 
              type="submit" 
              disabled={isPending} 
              className="ml-auto bg-indigo-500 hover:bg-indigo-600 text-white"
            >
              {isPending ? t("requesting") : t("requestChange")}
            </Button>
          </CardFooter>
        </form>
      )}
    </Card>
  )
}

"use client"

import { useState, useTransition } from "react"
import { useTranslations } from "next-intl"
import { toast } from "sonner"
import { 
  Card, 
  CardHeader, 
  CardTitle, 
  CardDescription, 
  CardContent, 
  CardFooter 
} from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { updateProfile } from "@/lib/settings-actions"

type ProfileFormProps = {
  user: {
    firstName: string
    lastName: string
    username: string
  }
}

export function ProfileForm({ user }: ProfileFormProps) {
  const t = useTranslations("settings.profile")
  const [isPending, startTransition] = useTransition()

  async function handleSubmit(formData: FormData) {
    // Basic frontend validation
    const username = formData.get("username") as string
    if (!/^[a-zA-Z0-9.\-_]+$/.test(username)) {
      toast.error("Username formatting is invalid")
      return
    }

    startTransition(async () => {
      const result = await updateProfile(formData)
      if (result.success) {
        toast.success(t("success"))
        if (typeof navigator !== "undefined" && navigator.vibrate) navigator.vibrate(50)
      } else {
        toast.error(result.error || t("error"))
      }
    })
  }

  return (
    <Card className="border-zinc-200 dark:border-zinc-800 bg-white/50 dark:bg-zinc-900/50 backdrop-blur-sm">
      <CardHeader>
        <CardTitle>{t("title")}</CardTitle>
        <CardDescription>{t("subtitle")}</CardDescription>
      </CardHeader>
      <form action={handleSubmit}>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="firstName">{t("firstName")}</Label>
              <Input 
                id="firstName" 
                name="firstName" 
                defaultValue={user.firstName}
                required 
                className="bg-zinc-50 dark:bg-zinc-800/50"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="lastName">{t("lastName")}</Label>
              <Input 
                id="lastName" 
                name="lastName" 
                defaultValue={user.lastName}
                required 
                className="bg-zinc-50 dark:bg-zinc-800/50"
              />
            </div>
          </div>
          <div className="space-y-2">
            <Label htmlFor="username">{t("username")}</Label>
            <Input 
              id="username" 
              name="username" 
              defaultValue={user.username}
              required 
              className="bg-zinc-50 dark:bg-zinc-800/50"
            />
            <p className="text-xs text-slate-500 dark:text-zinc-500">
              Only letters, numbers, dots, dashes, and underscores allowed. Must be unique.
            </p>
          </div>
        </CardContent>
        <CardFooter className="border-t border-zinc-200/50 dark:border-zinc-800/50 px-6 py-4">
          <Button type="submit" disabled={isPending} className="ml-auto bg-sky-600 hover:bg-sky-700 text-white">
            {isPending ? t("saving") : t("save")}
          </Button>
        </CardFooter>
      </form>
    </Card>
  )
}

"use client"

import { Suspense, useState, useEffect, useRef } from "react"
import { useSearchParams, useRouter } from "next/navigation"
import Link from "next/link"
import { useTranslations } from "next-intl"
import { CheckCircle2, AlertCircle, Loader2, Mail } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { confirmEmailChange } from "@/lib/settings-actions"

export default function VerifyEmailPage() {
  return (
    <div className="min-h-[80vh] flex items-center justify-center p-4">
      <Suspense 
        fallback={
          <div className="flex flex-col items-center justify-center p-12 space-y-4">
            <Loader2 className="h-10 w-10 animate-spin text-indigo-500" />
            <p className="text-sm text-slate-500">Loading verification data...</p>
          </div>
        }
      >
        <VerifyEmailContent />
      </Suspense>
    </div>
  )
}

function VerifyEmailContent() {
  const searchParams = useSearchParams()
  const token = searchParams.get("token")
  const identifier = searchParams.get("id")

  if (!token || !identifier) {
    return <InvalidLink />
  }

  return <VerificationProcess token={token} identifier={identifier} />
}

function VerificationProcess({ token, identifier }: { token: string; identifier: string }) {
  const t = useTranslations("settings.email")
  const router = useRouter()
  const [status, setStatus] = useState<"loading" | "success" | "error">("loading")
  const [errorMessage, setErrorMessage] = useState("")
  const [newEmail, setNewEmail] = useState("")
  const hasVerified = useRef(false)

  useEffect(() => {
    let isMounted = true

    async function verify() {
      if (hasVerified.current) return
      hasVerified.current = true

      const result = await confirmEmailChange(token, identifier)
      if (!isMounted) return

      if (result.success) {
        setStatus("success")
        setNewEmail(result.email!)
        if (typeof navigator !== "undefined" && navigator.vibrate) navigator.vibrate([30, 50, 30])
      } else {
        setStatus("error")
        setErrorMessage(result.error || t("verifyError"))
      }
    }

    verify()

    return () => { isMounted = false }
  }, [token, identifier, t])

  if (status === "loading") {
    return (
      <Card className="w-full max-w-md border-0 shadow-xl shadow-indigo-100/50 dark:shadow-none dark:border dark:border-zinc-800 dark:bg-zinc-900">
        <CardContent className="pt-10 pb-8 text-center space-y-6">
          <div className="mx-auto flex h-20 w-20 items-center justify-center rounded-full bg-indigo-50 dark:bg-indigo-500/10">
            <Loader2 className="h-10 w-10 animate-spin text-indigo-500" />
          </div>
          <div>
            <h2 className="text-xl font-bold text-slate-800 dark:text-zinc-100 mb-2">{t("verifyTitle")}</h2>
            <p className="text-slate-500 dark:text-zinc-400 text-sm max-w-xs mx-auto mb-6">{t("verifyDesc")}</p>
          </div>
        </CardContent>
      </Card>
    )
  }

  if (status === "success") {
    return (
      <Card className="w-full max-w-md border-0 shadow-xl shadow-emerald-100/50 dark:shadow-none dark:border dark:border-zinc-800 dark:bg-zinc-900 border-t-4 border-t-emerald-500">
        <CardContent className="pt-10 pb-8 text-center space-y-4">
          <div className="mx-auto flex h-16 w-16 items-center justify-center rounded-full bg-emerald-50 dark:bg-emerald-500/10 mb-2">
            <CheckCircle2 className="h-8 w-8 text-emerald-500" />
          </div>
          <h2 className="text-xl font-bold text-slate-800 dark:text-zinc-100">{t("verifySuccess")}</h2>
          <p className="text-slate-500 dark:text-zinc-400 text-sm font-medium bg-slate-50 dark:bg-zinc-800/50 p-3 rounded-md border border-slate-100 dark:border-zinc-800">
            {newEmail}
          </p>
        </CardContent>
        <CardFooter className="justify-center border-t border-slate-100 dark:border-zinc-800/50 pt-6">
          <Link href="/settings">
            <Button className="bg-slate-900 hover:bg-slate-800 dark:bg-zinc-100 dark:hover:bg-white dark:text-zinc-900 px-8">
              {t("backToSettings")}
            </Button>
          </Link>
        </CardFooter>
      </Card>
    )
  }

  return (
    <Card className="w-full max-w-md border-0 shadow-xl shadow-red-100/50 dark:shadow-none dark:border dark:border-zinc-800 dark:bg-zinc-900 border-t-4 border-t-red-500">
      <CardContent className="pt-10 pb-8 text-center space-y-4">
        <div className="mx-auto flex h-16 w-16 items-center justify-center rounded-full bg-red-50 dark:bg-red-500/10 mb-2">
          <AlertCircle className="h-8 w-8 text-red-500" />
        </div>
        <h2 className="text-xl font-bold text-slate-800 dark:text-zinc-100">Verification Failed</h2>
        <p className="text-red-500 dark:text-red-400 text-sm font-medium bg-red-50 dark:bg-red-500/10 p-3 rounded-md">
          {errorMessage}
        </p>
      </CardContent>
      <CardFooter className="justify-center border-t border-slate-100 dark:border-zinc-800/50 pt-6">
        <Link href="/settings">
          <Button variant="outline" className="px-8">
            {t("backToSettings")}
          </Button>
        </Link>
      </CardFooter>
    </Card>
  )
}

function InvalidLink() {
  const t = useTranslations("settings.email")
  return (
    <Card className="w-full max-w-md border-0 shadow-xl shadow-red-100/50 dark:shadow-none dark:border dark:border-zinc-800 dark:bg-zinc-900 border-t-4 border-t-red-500">
      <CardContent className="pt-10 pb-8 text-center space-y-4">
        <div className="mx-auto flex h-16 w-16 items-center justify-center rounded-full bg-red-50 dark:bg-red-500/10 mb-2">
          <AlertCircle className="h-8 w-8 text-red-500" />
        </div>
        <h2 className="text-xl font-bold text-slate-800 dark:text-zinc-100">Invalid Link</h2>
        <p className="text-slate-500 dark:text-zinc-400 text-sm">{t("verifyError")}</p>
      </CardContent>
      <CardFooter className="justify-center border-t border-slate-100 dark:border-zinc-800/50 pt-6">
        <Link href="/settings">
          <Button variant="outline" className="px-8">{t("backToSettings")}</Button>
        </Link>
      </CardFooter>
    </Card>
  )
}

import { auth } from "@/lib/auth"
import { getTranslations } from "next-intl/server"
import { redirect } from "next/navigation"
import Link from "next/link"
import { AdminUserNav } from "./admin-user-nav"

export default async function AdminLayout({
  children,
}: {
  children: React.ReactNode
}) {
  const session = await auth()
  const t = await getTranslations("admin")

  if (!session?.user || session.user.role !== "ADMIN") {
    redirect("/login")
  }

  return (
    <div className="min-h-svh bg-zinc-950 text-zinc-50">
      <header className="border-b border-zinc-800/50 bg-zinc-950/80 backdrop-blur-sm">
        <div className="mx-auto flex h-16 max-w-7xl items-center justify-between px-6">
          <div className="flex items-center gap-3">
            <Link href="/" className="text-lg font-bold tracking-tight text-sky-400 hover:text-sky-300 transition-colors">
              flyteLog
            </Link>
            <span className="rounded-md bg-zinc-800 px-2 py-0.5 text-[11px] font-medium uppercase tracking-wider text-zinc-400">
              Admin
            </span>
          </div>
          <AdminUserNav 
            user={{
              firstName: session.user.firstName,
              lastName: session.user.lastName,
              username: session.user.username,
              email: session.user.email,
              avatarColor: session.user.avatarColor,
              role: session.user.role,
            }} 
          />
        </div>
      </header>
      <main className="mx-auto max-w-7xl px-6 py-8">{children}</main>
    </div>
  )
}

import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import axios from 'axios';

const API_KEY = process.env.OPENAIP_API_KEY;
const BASE_URL = 'https://api.core.openaip.net/api';
const HEADERS = {
  'x-openaip-api-key': API_KEY || '',
  Accept: 'application/json',
};

async function fetchPaginated(endpoint: string, country = 'PL', limit = 10) {
  let results: any[] = [];
  let page = 1;
  let totalPages = 1;

  while (page <= Math.min(totalPages, limit)) {
    console.log(`Fetching ${endpoint} page ${page}...`);
    try {
      const res = await axios.get(`${BASE_URL}${endpoint}`, {
        params: { country, page },
        headers: HEADERS,
      });

      results = results.concat(res.data.items);
      totalPages = res.data.pageCount || 1;
      page++;
    } catch (err: any) {
      console.error(`Error on ${endpoint} page ${page}:`, err.response?.data || err.message);
      break;
    }
  }
  return results;
}

function chunkArray<T>(arr: T[], size: number): T[][] {
  return Array.from({ length: Math.ceil(arr.length / size) }, (v, i) => arr.slice(i * size, i * size + size));
}

export async function GET() {
  if (!API_KEY) return NextResponse.json({ error: 'OPENAIP_API_KEY missing' }, { status: 500 });

  try {
    console.log('--- STARTING COMPREHENSIVE OPENAIP SYNC ---');

    // 1. Airports
    console.log('Fetching airports...');
    const airports = await fetchPaginated('/airports', 'PL', 5);
    await prisma.$transaction(async tx => {
      await tx.airport.deleteMany({ where: { country: 'PL' } });
      const records = airports.map(a => ({
        openaipId: a._id,
        name: a.name,
        icaoCode: a.icaoCode,
        type: a.type,
        lat: a.geometry.coordinates[1],
        lon: a.geometry.coordinates[0],
        elevation: a.elevation?.value,
        country: a.country,
      }));
      await tx.airport.createMany({ data: records });
    });

    // 2. Navaids
    console.log('Fetching navaids...');
    const navaids = await fetchPaginated('/navaids', 'PL', 5);
    await prisma.$transaction(async tx => {
      await tx.navaid.deleteMany({ where: { country: 'PL' } });
      const records = navaids.map(n => ({
        openaipId: n._id,
        name: n.name,
        type: n.type,
        frequency: n.frequency?.value ? n.frequency.value.toString() : null,
        lat: n.geometry.coordinates[1],
        lon: n.geometry.coordinates[0],
        elevation: n.elevation?.value,
        country: n.country,
      }));
      await tx.navaid.createMany({ data: records });
    });

    // 3. Airspaces
    console.log('Fetching airspaces...');
    const airspaces = await fetchPaginated('/airspaces', 'PL', 25);
    await prisma.$transaction(async tx => {
      await tx.airspace.deleteMany({ where: { country: 'PL' } });
      const records = airspaces.map(as => ({
        openaipId: as._id,
        name: as.name,
        type: as.type,
        icaoClass: as.icaoClass,
        upperLimit: as.upperLimit?.value,
        lowerLimit: as.lowerLimit?.value,
        country: as.country,
        geometry: as.geometry,
      }));
      for (const chunk of chunkArray(records, 20)) {
        await tx.airspace.createMany({ data: chunk });
      }
    });

    // 4. Reporting Points
    console.log('Fetching reporting points...');
    const rps = await fetchPaginated('/reporting-points', 'PL', 10);
    await prisma.$transaction(async tx => {
      await tx.reportingPoint.deleteMany({ where: { country: 'PL' } });
      const records = rps.map(rp => ({
        openaipId: rp._id,
        name: rp.name,
        type: rp.type ?? null,
        lat: rp.geometry.coordinates[1],
        lon: rp.geometry.coordinates[0],
        elevation: rp.elevation?.value,
        country: rp.country,
      }));
      await tx.reportingPoint.createMany({ data: records });
    });

    // 5. Obstacles
    console.log('Fetching obstacles...');
    const obstacles = await fetchPaginated('/obstacles', 'PL', 20);
    await prisma.$transaction(async tx => {
      await tx.obstacle.deleteMany({ where: { country: 'PL' } });
      const records = obstacles.map(o => ({
        openaipId: o._id,
        type: o.type,
        lat: o.geometry.coordinates[1],
        lon: o.geometry.coordinates[0],
        elevation: o.elevation?.value || 0,
        heightAgl: o.heightAgl || 0,
        country: o.country || 'PL',
      }));
      for (const chunk of chunkArray(records, 50)) {
        await tx.obstacle.createMany({ data: chunk });
      }
    });

    await prisma.syncLog.create({
      data: {
        source: 'OpenAIP',
        itemsUpdated: airports.length + navaids.length + airspaces.length + rps.length + obstacles.length,
      },
    });

    console.log('--- SYNC COMPLETE ---');
    return NextResponse.json({
      success: true,
      counts: {
        airports: airports.length,
        navaids: navaids.length,
        airspaces: airspaces.length,
        reportingPoints: rps.length,
        obstacles: obstacles.length,
      },
    });
  } catch (err: any) {
    console.error('OPENAIP SYNC ERROR:', err.response?.data || err.message || err);
    return NextResponse.json(
      {
        error: err.message,
        details: err.response?.data,
        stack: err.stack,
      },
      { status: 500 }
    );
  }
}

'use client';

import { useState, useRef, useCallback } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { Plane, Send, Monitor, Route, FileText, CloudSun, Home } from 'lucide-react';
import { useTranslations } from 'next-intl';
import { motion, AnimatePresence } from 'motion/react';

const tabs = [
  { key: 'aircraft', href: '/logbook/aircraft', icon: Plane },
  { key: 'glider', href: '/logbook/glider', icon: Send },
  { key: 'fstd', href: '/logbook/fstd', icon: Monitor },
  { key: 'route', href: '/plan/route', icon: Route },
  { key: 'ofp', href: '/plan/ofp', icon: FileText },
  { key: 'weather', href: '/plan/weather', icon: CloudSun },
] as const;

const HIDE_DELAY_MS = 1000;

export function FeatureTabs() {
  const pathname = usePathname();
  const t = useTranslations('tabs');
  const [isVisible, setIsVisible] = useState(false);
  const hideTimerRef = useRef<ReturnType<typeof setTimeout>>(null);

  const clearHideTimer = useCallback(() => {
    if (hideTimerRef.current) {
      clearTimeout(hideTimerRef.current);
      hideTimerRef.current = null;
    }
  }, []);

  const handleMouseEnter = useCallback(() => {
    clearHideTimer();
    setIsVisible(true);
  }, [clearHideTimer]);

  const handleMouseLeave = useCallback(() => {
    clearHideTimer();
    hideTimerRef.current = setTimeout(() => setIsVisible(false), HIDE_DELAY_MS);
  }, [clearHideTimer]);

  return (
    <div onMouseEnter={handleMouseEnter} onMouseLeave={handleMouseLeave} className='absolute left-1/2 -translate-x-1/2 z-40 flex flex-col items-center px-8'>
      {/* Invisible hover trigger zone — always present */}
      <div className='h-3 -mx-1 w-max' />

      <motion.nav
        initial={false}
        animate={isVisible ? { y: 0, opacity: 1, scaleY: 1 } : { y: -20, opacity: 0, scaleY: 0.95 }}
        transition={{ type: 'spring', stiffness: 400, damping: 30 }}
        className={`origin-top mx-auto w-fit rounded-xl bg-white/75 dark:bg-zinc-900/75 backdrop-blur-lg shadow-lg shadow-slate-200/50 dark:shadow-zinc-950/50 ${
          isVisible ? 'pointer-events-auto' : 'pointer-events-none'
        }`}
      >
        <div className='flex items-center gap-1 p-2'>
          {tabs.map(({ key, href, icon: Icon }) => {
            const isActive = pathname.startsWith(href);

            return (
              <Link
                key={key}
                href={href}
                className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-colors select-none whitespace-nowrap ${
                  isActive
                    ? 'bg-sky-100 dark:bg-sky-500/15 text-sky-600 dark:text-sky-400'
                    : 'text-slate-500 dark:text-zinc-400 hover:bg-slate-100 dark:hover:bg-zinc-800 hover:text-slate-700 dark:hover:text-zinc-300'
                }`}
              >
                <Icon className='h-4 w-4 shrink-0' />
                <span className='hidden sm:inline'>{t(key)}</span>
              </Link>
            );
          })}
        </div>
      </motion.nav>

      {/* Bottom padding zone for easier mouse interaction */}
      <div className='h-6 w-full' />
    </div>
  );
}

