'use client';

import { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  ChevronDown,
  ChevronLeft,
  Download,
  X,
  AlertTriangle,
  Minus,
  Search,
  GripVertical,
  PlaneTakeoff,
  PlaneLanding,
  Plus,
  Layers,
  Mountain,
  Navigation,
  MapPin,
  TrafficCone,
  SquareDot,
  Triangle,
  Radio,
  Flag,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { useTranslations } from 'next-intl';
import { useRoute } from '@/components/route/route-context';
import { useAeroData, type WaypointSearchResult } from '@/hooks/use-aero-data';
import { TerrainProfileChart } from '@/components/route/terrain-profile';
import { getTerrainProfile, type TerrainSample } from '@/lib/terrain';
import { computeNavlog, type NavlogEntry } from '@/lib/navlog';
import { Tooltip, TooltipContent, TooltipTrigger } from '@/components/ui/tooltip';

export interface LayerState {
  airspaceTypes: Record<number, boolean>;
  altitudeRange: [number, number];
  showTerrain: boolean;
  terrainOpacity: number;
  showAirports: boolean;
  showNavaids: boolean;
  showObstacles: boolean;
  showReportingPoints: boolean;
}

// ---------------------------------------------------------------------------
// OpenAIP type number reference (actual values from /api/aero-data):
//  1=R, 2=D, 3=P, 4=CTR, 5=TMZ, 6=RMZ, 7=TMA, 8=TRA, 9=TSA,
//  10=FIR, 13=ATZ, 18=BVLOS, 21=LFA, 28=SPORT, 30=MRT, 33=NPZ
// ---------------------------------------------------------------------------

const DEFAULT_LAYERS: LayerState = {
  airspaceTypes: {
    9: false,
    8: false,
    2: false,
    13: false,
    30: false,
    33: false,
    1: false,
    4: false,
    7: false,
    3: false,
    6: false,
    5: false,
    18: false,
    21: false,
    28: false,
  },
  altitudeRange: [0, 9500],
  showTerrain: false,
  terrainOpacity: 0.5,
  showAirports: false,
  showNavaids: false,
  showObstacles: false,
  showReportingPoints: false,
};

interface AirspaceTypeConfig {
  type: number;
  label: string;
  color: string;
}

/**
 * AUP-activated / dynamic airspaces.
 * Zarządzane elastycznie przez AUP — aktywowane na bieżąco.
 */
const DYNAMIC_TYPES: AirspaceTypeConfig[] = [
  { type: 9, label: 'TSA', color: '#ef4444' }, // 43 records
  { type: 8, label: 'TRA', color: '#f97316' }, // 246 records
  { type: 2, label: 'D', color: '#a855f7' }, // 28 records
  { type: 13, label: 'ATZ', color: '#22c55e' }, // 50 records
  { type: 30, label: 'MRT', color: '#6366f1' }, // 151 records
  { type: 33, label: 'NPZ', color: '#64748b' }, // 9 records
];

/**
 * Static / always-active airspaces.
 * Zawsze aktywne — stałe struktury przestrzeni powietrznej.
 */
const STATIC_TYPES: AirspaceTypeConfig[] = [
  { type: 1, label: 'R', color: '#dc2626' }, // 28 records
  { type: 4, label: 'CTR', color: '#3b82f6' }, // 31 records
  { type: 7, label: 'TMA', color: '#0ea5e9' }, // 75 records
  { type: 3, label: 'P', color: '#7f1d1d' }, // 32 records
];

/**
 * Informational / recreational airspaces — off by default.
 * Strefy informacyjne i rekreacyjne.
 */
const OTHER_TYPES: AirspaceTypeConfig[] = [
  { type: 6, label: 'RMZ', color: '#94a3b8' }, // 69 records
  { type: 5, label: 'TMZ', color: '#818cf8' }, // 1 record
  { type: 18, label: 'BVLOS', color: '#f59e0b' }, // 35 records
  { type: 21, label: 'LFA', color: '#84cc16' }, // 47 records
  { type: 28, label: 'SPORT', color: '#ec4899' }, // 106 records
];

/**
 * Format altitude for the sidebar slider label.
 * 0 ft      → "GND"
 * 1–6500 ft → A-prefix in hundreds, e.g. A15, A65
 * ≥7000 ft  → FL-prefix, e.g. FL070, FL245
 * ≥66000 ft → "UNL"
 */
function formatAltFt(ft: number): string {
  if (ft === 0) return 'GND';
  if (ft >= 66000) return 'UNL';
  if (ft <= 6500) return `A${Math.round(ft / 100)}`;
  const fl = Math.round(ft / 100);
  return `FL${String(fl).padStart(3, '0')}`;
}

interface MapSidebarProps {
  onLayerChange: (layers: LayerState) => void;
}

export function MapSidebar({ onLayerChange }: MapSidebarProps) {
  const t = useTranslations('map');
  const [isExpanded, setIsExpanded] = useState(false);
  // Which accordion sections are open (multiple can be open simultaneously)
  const [openSections, setOpenSections] = useState<Set<string>>(new Set(['route']));
  const [layers, setLayers] = useState<LayerState>(DEFAULT_LAYERS);
  const [terrainProfile, setTerrainProfile] = useState<TerrainSample[]>([]);
  const [navlogEntries, setNavlogEntries] = useState<NavlogEntry[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<WaypointSearchResult[]>([]);
  const [showEnrouteSearch, setShowEnrouteSearch] = useState(false);
  const [isSyncingAup, setIsSyncingAup] = useState(false);
  const [aupLastSync, setAupLastSync] = useState<Date | null>(null);

  const toggleSection = useCallback((id: string) => {
    setOpenSections(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  }, []);

  const { waypoints, legs, departure, destination, removeWaypoint, setDeparture, setDestination, addEnroute, reorderWaypoints, setLegAltitude, clearRoute } =
    useRoute();
  const { isOffline, isDownloading, downloadForOffline, lastDownloadDate, searchWaypoints } = useAeroData();

  const [dragIndex, setDragIndex] = useState<number | null>(null);

  useEffect(() => {
    if (waypoints.length < 2) {
      setTerrainProfile([]);
      setNavlogEntries([]);
      return;
    }
    const compute = async () => {
      const profile = await getTerrainProfile(waypoints);
      setTerrainProfile(profile);
      const entries = computeNavlog(legs, profile, legs[0]?.altitudeFt ?? 3500);
      setNavlogEntries(entries);
    };
    compute();
  }, [waypoints, legs]);

  useEffect(() => {
    onLayerChange(layers);
  }, [layers, onLayerChange]);

  const updateLayer = useCallback(<K extends keyof LayerState>(key: K, value: LayerState[K]) => {
    setLayers(prev => ({ ...prev, [key]: value }));
  }, []);

  const toggleAirspaceType = useCallback((type: number) => {
    setLayers(prev => ({
      ...prev,
      airspaceTypes: { ...prev.airspaceTypes, [type]: !prev.airspaceTypes[type] },
    }));
  }, []);

  const handleAupSync = useCallback(async () => {
    setIsSyncingAup(true);
    try {
      await fetch('/api/aup/sync', { method: 'POST' });
      setAupLastSync(new Date());
      if (typeof navigator !== 'undefined' && navigator.vibrate) navigator.vibrate(50);
    } catch (err) {
      console.error('[AUP sync]', err);
    } finally {
      setIsSyncingAup(false);
    }
  }, []);

  useEffect(() => {
    if (searchQuery.length < 2) {
      setSearchResults([]);
      return;
    }
    const timeout = setTimeout(() => {
      searchWaypoints(searchQuery).then(setSearchResults);
    }, 200);
    return () => clearTimeout(timeout);
  }, [searchQuery, searchWaypoints]);

  const handleSearchSelect = useCallback(
    (result: WaypointSearchResult, role: 'departure' | 'waypoint' | 'destination') => {
      const wp = {
        name: result.icao ? `${result.name} (${result.icao})` : result.name,
        lat: result.lat,
        lon: result.lon,
        elev: result.elev,
        type: result.type,
      };
      if (role === 'departure') setDeparture(wp);
      else if (role === 'destination') setDestination(wp);
      else addEnroute(wp);
      setSearchQuery('');
      setSearchResults([]);
      setShowEnrouteSearch(false);
    },
    [setDeparture, setDestination, addEnroute],
  );

  const handleDragStart = (index: number) => setDragIndex(index);
  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (dragIndex === null || dragIndex === index) return;
    reorderWaypoints(dragIndex, index);
    setDragIndex(index);
  };
  const handleDragEnd = () => setDragIndex(null);

  const totalDistance = legs.reduce((sum, l) => sum + l.distanceNM, 0);

  return (
    <motion.div
      initial={{ width: 56 }}
      animate={{ width: isExpanded ? 380 : 56 }}
      transition={{ type: 'spring', stiffness: 400, damping: 30 }}
      className='absolute top-0 left-0 z-40 h-full flex flex-col rounded-none shadow-xl overflow-hidden select-none border-r border-border bg-background'
    >
      {/* Icon strip — always visible */}
      <div className='flex flex-col shrink-0 py-2 gap-1'>
        <SidebarIconButton
          icon={PlaneTakeoff}
          active={isExpanded && openSections.has('route')}
          label={t('route')}
          isExpanded={isExpanded}
          onClick={() => {
            if (!isExpanded) {
              setIsExpanded(true);
              setOpenSections(new Set(['route']));
            } else toggleSection('route');
          }}
        />
        <SidebarIconButton
          icon={Layers}
          active={isExpanded && openSections.has('layers')}
          label={t('layers')}
          isExpanded={isExpanded}
          onClick={() => {
            if (!isExpanded) {
              setIsExpanded(true);
              setOpenSections(new Set(['layers']));
            } else toggleSection('layers');
          }}
        />

        {isExpanded && (
          <button
            onClick={() => setIsExpanded(false)}
            className='flex h-10 w-10 items-center justify-center self-end mr-1 text-slate-400 hover:text-slate-600 dark:hover:text-zinc-300 transition-colors rounded-lg hover:bg-slate-100 dark:hover:bg-zinc-800'
          >
            <ChevronLeft className='h-4 w-4' />
          </button>
        )}
      </div>

      <div className='mx-3 h-px bg-slate-200/80 dark:bg-zinc-700/80 shrink-0' />

      {/* Accordion content */}
      {isExpanded && (
        <div className='flex-1 overflow-y-auto px-3 py-2 flex flex-col gap-0'>
          <AccordionSection id='route' icon={PlaneTakeoff} title={t('route')} isOpen={openSections.has('route')} onToggle={toggleSection}>
            <RouteTab
              departure={departure}
              destination={destination}
              waypoints={waypoints}
              legs={legs}
              navlogEntries={navlogEntries}
              terrainProfile={terrainProfile}
              totalDistance={totalDistance}
              searchQuery={searchQuery}
              searchResults={searchResults}
              showEnrouteSearch={showEnrouteSearch}
              dragIndex={dragIndex}
              onSearchChange={setSearchQuery}
              onSearchSelect={handleSearchSelect}
              onToggleEnrouteSearch={() => setShowEnrouteSearch(!showEnrouteSearch)}
              onRemoveWaypoint={removeWaypoint}
              onSetLegAltitude={setLegAltitude}
              onClearRoute={clearRoute}
              onDragStart={handleDragStart}
              onDragOver={handleDragOver}
              onDragEnd={handleDragEnd}
              t={t}
            />
          </AccordionSection>

          <AccordionSection id='layers' icon={Layers} title={t('layers')} isOpen={openSections.has('layers')} onToggle={toggleSection}>
            <LayersTab
              layers={layers}
              onToggleAirspaceType={toggleAirspaceType}
              onUpdateLayer={updateLayer}
              isOffline={isOffline}
              isDownloading={isDownloading}
              onDownload={downloadForOffline}
              lastDownloadDate={lastDownloadDate}
              isSyncingAup={isSyncingAup}
              aupLastSync={aupLastSync}
              onAupSync={handleAupSync}
              t={t}
            />
          </AccordionSection>
        </div>
      )}
    </motion.div>
  );
}

function SidebarIconButton({
  icon: Icon,
  active,
  label,
  isExpanded,
  onClick,
}: {
  icon: React.ElementType;
  active: boolean;
  label: string;
  isExpanded: boolean;
  onClick: () => void;
}) {
  const content = (
    <button
      onClick={onClick}
      className={`flex items-center gap-2 mx-2 px-2 h-10 rounded-xl text-sm font-medium transition-colors ${
        active
          ? 'bg-sky-100 dark:bg-sky-500/20 text-sky-600 dark:text-sky-400'
          : 'text-slate-500 dark:text-zinc-400 hover:bg-slate-100 dark:hover:bg-zinc-800 hover:text-slate-700 dark:hover:text-zinc-200'
      } ${isExpanded ? 'w-auto' : 'w-10 justify-center'}`}
    >
      <Icon className='h-4 w-4 shrink-0' />
      {isExpanded && <span className='text-xs truncate'>{label}</span>}
    </button>
  );

  if (isExpanded) return content;

  return (
    <Tooltip>
      <TooltipTrigger asChild>{content}</TooltipTrigger>
      <TooltipContent side='right'>
        <p>{label}</p>
      </TooltipContent>
    </Tooltip>
  );
}

function AccordionSection({
  id,
  icon: Icon,
  title,
  isOpen,
  onToggle,
  children,
}: {
  id: string;
  icon: React.ElementType;
  title: string;
  isOpen: boolean;
  onToggle: (id: string) => void;
  children: React.ReactNode;
}) {
  return (
    <div className='border-b border-slate-200/60 dark:border-zinc-700/60 last:border-0'>
      <button onClick={() => onToggle(id)} className='flex items-center justify-between w-full py-2.5 text-left group'>
        <div className='flex items-center gap-2'>
          <Icon className='h-3.5 w-3.5 text-slate-500 dark:text-zinc-400 shrink-0' />
          <span className='text-xs font-semibold text-slate-600 dark:text-zinc-300 uppercase tracking-wider'>{title}</span>
        </div>
        <ChevronDown className={`h-3.5 w-3.5 text-slate-400 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
      </button>
      <AnimatePresence initial={false}>
        {isOpen && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.2, ease: 'easeInOut' }}
            className='overflow-hidden'
          >
            <div className='pb-3 flex flex-col gap-3'>{children}</div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

function SearchInput({
  value,
  onChange,
  placeholder,
  results,
  onSelect,
  roleFilter,
}: {
  value: string;
  onChange: (v: string) => void;
  placeholder: string;
  results: WaypointSearchResult[];
  onSelect: (r: WaypointSearchResult, role: 'departure' | 'waypoint' | 'destination') => void;
  roleFilter: 'departure' | 'waypoint' | 'destination';
}) {
  return (
    <div className='relative'>
      <div className='flex items-center gap-2 rounded-lg bg-slate-100 dark:bg-zinc-800 px-2.5 py-2 border border-slate-200 dark:border-zinc-700'>
        <Search className='h-3.5 w-3.5 text-slate-400 shrink-0' />
        <input
          type='text'
          value={value}
          onChange={e => onChange(e.target.value)}
          placeholder={placeholder}
          className='flex-1 bg-transparent text-xs text-slate-800 dark:text-zinc-200 focus:outline-none'
        />
        {value && (
          <button onClick={() => onChange('')} className='text-slate-400 hover:text-slate-600'>
            <X className='h-3 w-3' />
          </button>
        )}
      </div>
      {results.length > 0 && (
        <div className='absolute left-0 right-0 top-full mt-1 rounded-lg bg-white dark:bg-zinc-800 shadow-lg border border-slate-200 dark:border-zinc-700 z-50 max-h-48 overflow-y-auto'>
          {results.map((r, i) => (
            <button
              key={`${r.type}-${i}`}
              onClick={() => onSelect(r, roleFilter)}
              className='w-full flex items-center gap-2 px-3 py-2 text-xs hover:bg-slate-50 dark:hover:bg-zinc-700 transition-colors text-left'
            >
              <span className='text-slate-800 dark:text-zinc-200 font-medium truncate'>{r.name}</span>
              {r.icao && <span className='text-slate-400 shrink-0'>({r.icao})</span>}
              <span className='ml-auto text-[10px] text-slate-400 capitalize shrink-0'>{r.type}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function RouteTab({
  departure,
  destination,
  waypoints,
  legs,
  navlogEntries,
  terrainProfile,
  totalDistance,
  searchQuery,
  searchResults,
  showEnrouteSearch,
  dragIndex,
  onSearchChange,
  onSearchSelect,
  onToggleEnrouteSearch,
  onRemoveWaypoint,
  onSetLegAltitude,
  onClearRoute,
  onDragStart,
  onDragOver,
  onDragEnd,
  t,
}: any) {
  const [depSearch, setDepSearch] = useState('');
  const [destSearch, setDestSearch] = useState('');
  const [depResults, setDepResults] = useState<WaypointSearchResult[]>([]);
  const [destResults, setDestResults] = useState<WaypointSearchResult[]>([]);
  const { searchWaypoints } = useAeroData();

  useEffect(() => {
    if (depSearch.length < 2) {
      setDepResults([]);
      return;
    }
    const t = setTimeout(() => searchWaypoints(depSearch).then(setDepResults), 200);
    return () => clearTimeout(t);
  }, [depSearch, searchWaypoints]);

  useEffect(() => {
    if (destSearch.length < 2) {
      setDestResults([]);
      return;
    }
    const t = setTimeout(() => searchWaypoints(destSearch).then(setDestResults), 200);
    return () => clearTimeout(t);
  }, [destSearch, searchWaypoints]);

  return (
    <>
      {/* Departure */}
      <div>
        <label className='flex items-center gap-1.5 text-xs font-medium text-slate-500 dark:text-zinc-400 mb-1'>
          <PlaneTakeoff className='h-3 w-3 text-green-500' />
          {t('departureAirport')}
        </label>
        {departure ? (
          <div className='flex items-center gap-2 rounded-lg bg-green-50 dark:bg-green-500/10 px-2.5 py-2 text-xs'>
            <span className='flex-1 font-medium text-green-700 dark:text-green-400 truncate'>{departure.name}</span>
            <button onClick={() => onRemoveWaypoint(0)} className='text-green-400 hover:text-red-500 transition-colors'>
              <X className='h-3 w-3' />
            </button>
          </div>
        ) : (
          <SearchInput
            value={depSearch}
            onChange={setDepSearch}
            placeholder={t('searchDeparture')}
            results={depResults}
            onSelect={(r, _) => {
              onSearchSelect(r, 'departure');
              setDepSearch('');
            }}
            roleFilter='departure'
          />
        )}
      </div>

      {/* Waypoints */}
      <div>
        <div className='flex items-center justify-between mb-1'>
          <label className='flex items-center gap-1.5 text-xs font-medium text-slate-500 dark:text-zinc-400'>
            <MapPin className='h-3 w-3 text-sky-500' />
            {t('waypoints')} ({waypoints.filter((w: any) => w.role === 'waypoint').length})
          </label>
          <div className='flex gap-1'>
            <button onClick={onToggleEnrouteSearch} className='text-sky-500 hover:text-sky-600 transition-colors'>
              <Plus className='h-3.5 w-3.5' />
            </button>
            {waypoints.length > 0 && (
              <button onClick={onClearRoute} className='text-xs text-red-500 hover:text-red-600 transition-colors'>
                {t('clearAll')}
              </button>
            )}
          </div>
        </div>

        {showEnrouteSearch && (
          <div className='mb-2'>
            <SearchInput
              value={searchQuery}
              onChange={onSearchChange}
              placeholder={t('searchWaypoint')}
              results={searchResults}
              onSelect={(r, _) => onSearchSelect(r, 'waypoint')}
              roleFilter='waypoint'
            />
          </div>
        )}

        <div className='flex flex-col gap-1'>
          {waypoints
            .filter((w: any) => w.role === 'waypoint')
            .map((wp: any, i: number) => {
              const realIndex = waypoints.indexOf(wp);
              return (
                <div
                  key={wp.id}
                  draggable
                  onDragStart={() => onDragStart(realIndex)}
                  onDragOver={(e: React.DragEvent) => onDragOver(e, realIndex)}
                  onDragEnd={onDragEnd}
                  className={`flex items-center gap-1.5 rounded-lg bg-slate-50 dark:bg-zinc-800/80 px-2 py-1.5 text-xs cursor-grab active:cursor-grabbing ${
                    dragIndex === realIndex ? 'opacity-50' : ''
                  }`}
                >
                  <GripVertical className='h-3 w-3 text-slate-300 dark:text-zinc-600 shrink-0' />
                  <span className='flex h-4 w-4 shrink-0 items-center justify-center rounded-full bg-sky-500 text-[9px] font-bold text-white'>{i + 1}</span>
                  <span className='flex-1 truncate text-slate-700 dark:text-zinc-300'>{wp.name}</span>
                  <button onClick={() => onRemoveWaypoint(realIndex)} className='shrink-0 text-slate-400 hover:text-red-500 transition-colors'>
                    <Minus className='h-3 w-3' />
                  </button>
                </div>
              );
            })}
        </div>
      </div>

      {/* Destination */}
      <div>
        <label className='flex items-center gap-1.5 text-xs font-medium text-slate-500 dark:text-zinc-400 mb-1'>
          <PlaneLanding className='h-3 w-3 text-red-500' />
          {t('destinationAirport')}
        </label>
        {destination ? (
          <div className='flex items-center gap-2 rounded-lg bg-red-50 dark:bg-red-500/10 px-2.5 py-2 text-xs'>
            <span className='flex-1 font-medium text-red-700 dark:text-red-400 truncate'>{destination.name}</span>
            <button onClick={() => onRemoveWaypoint(waypoints.length - 1)} className='text-red-400 hover:text-red-500 transition-colors'>
              <X className='h-3 w-3' />
            </button>
          </div>
        ) : (
          <SearchInput
            value={destSearch}
            onChange={setDestSearch}
            placeholder={t('searchDestination')}
            results={destResults}
            onSelect={(r, _) => {
              onSearchSelect(r, 'destination');
              setDestSearch('');
            }}
            roleFilter='destination'
          />
        )}
      </div>

      {/* Per-Leg Altitude */}
      {legs.length > 0 && (
        <div>
          <h4 className='text-xs font-medium text-slate-500 dark:text-zinc-400 uppercase tracking-wider mb-1.5'>{t('legAltitudes')}</h4>
          <div className='flex flex-col gap-1'>
            {legs.map((leg: any, i: number) => (
              <div key={i} className='flex items-center gap-2 text-xs'>
                <span className='w-16 truncate text-slate-500 dark:text-zinc-400'>{i + 1}.</span>
                <input
                  type='number'
                  value={leg.altitudeFt}
                  onChange={e => onSetLegAltitude(i, Number(e.target.value))}
                  step={500}
                  min={500}
                  className='w-20 rounded bg-slate-100 dark:bg-zinc-800 px-2 py-1 text-xs border border-slate-200 dark:border-zinc-700 focus:outline-none focus:ring-1 focus:ring-sky-500 text-slate-800 dark:text-zinc-200'
                />
                <span className='text-slate-400'>ft</span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Navlog */}
      {navlogEntries.length > 0 && (
        <div>
          <h4 className='text-xs font-medium text-slate-500 dark:text-zinc-400 uppercase tracking-wider mb-1.5'>Navlog</h4>
          <div className='rounded-lg overflow-hidden border border-slate-200 dark:border-zinc-700'>
            <table className='w-full text-[11px]'>
              <thead>
                <tr className='bg-slate-100 dark:bg-zinc-800'>
                  <th className='px-2 py-1 text-left font-medium text-slate-500 dark:text-zinc-400'>#</th>
                  <th className='px-2 py-1 text-right font-medium text-slate-500 dark:text-zinc-400'>NM</th>
                  <th className='px-2 py-1 text-right font-medium text-slate-500 dark:text-zinc-400'>MT°</th>
                  <th className='px-2 py-1 text-right font-medium text-slate-500 dark:text-zinc-400'>Alt</th>
                  <th className='px-2 py-1 text-center font-medium text-slate-500 dark:text-zinc-400'>⚠</th>
                </tr>
              </thead>
              <tbody>
                {navlogEntries.map((entry: NavlogEntry) => (
                  <tr
                    key={entry.legIndex}
                    className={`border-t border-slate-100 dark:border-zinc-800 ${entry.isBelowSafe ? 'bg-red-50 dark:bg-red-900/20' : ''}`}
                  >
                    <td className='px-2 py-1 text-slate-700 dark:text-zinc-300'>{entry.legIndex + 1}</td>
                    <td className='px-2 py-1 text-right text-slate-600 dark:text-zinc-400'>{entry.distanceNM}</td>
                    <td className='px-2 py-1 text-right text-slate-600 dark:text-zinc-400'>{entry.magneticTrack}°</td>
                    <td className='px-2 py-1 text-right text-slate-600 dark:text-zinc-400'>{legs[entry.legIndex]?.altitudeFt}</td>
                    <td className='px-2 py-1 text-center'>{entry.isBelowSafe && <AlertTriangle className='h-3 w-3 text-red-500 inline' />}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <p className='mt-1 text-[10px] text-slate-400 dark:text-zinc-500'>
            {t('totalDistance')}: {totalDistance.toFixed(1)} NM
          </p>
        </div>
      )}

      {/* Terrain */}
      {terrainProfile.length > 0 && (
        <div>
          <h4 className='text-xs font-medium text-slate-500 dark:text-zinc-400 uppercase tracking-wider mb-1.5'>{t('terrainProfile')}</h4>
          <TerrainProfileChart profile={terrainProfile} plannedAltitudeFt={legs[0]?.altitudeFt ?? 3500} width={340} height={140} />
        </div>
      )}
    </>
  );
}

function AirspaceTypeGrid({ types, layers, onToggle }: { types: AirspaceTypeConfig[]; layers: LayerState; onToggle: (t: number) => void }) {
  return (
    <div className='grid grid-cols-3 gap-1.5'>
      {types.map(({ type, label, color }) => {
        const active = layers.airspaceTypes[type] ?? false;
        return (
          <button
            key={type}
            onClick={() => onToggle(type)}
            className={`flex items-center gap-1.5 px-2 py-1.5 rounded-lg text-xs font-semibold transition-colors select-none border ${
              active
                ? 'bg-white dark:bg-zinc-800 shadow-sm border-slate-200 dark:border-zinc-600'
                : 'bg-slate-100/70 dark:bg-zinc-800/50 border-slate-200 dark:border-zinc-700/60'
            }`}
          >
            <span className='w-2 h-2 rounded-sm shrink-0 transition-colors' style={{ backgroundColor: active ? color : '#9ca3af' }} />
            <span className='transition-colors' style={{ color: active ? color : '#9ca3af' }}>
              {label}
            </span>
          </button>
        );
      })}
    </div>
  );
}

function LayersTab({
  layers,
  onToggleAirspaceType,
  onUpdateLayer,
  isOffline,
  isDownloading,
  onDownload,
  lastDownloadDate,
  isSyncingAup,
  aupLastSync,
  onAupSync,
  t,
}: any) {
  return (
    <>
      {/* Dynamic Airspaces (AUP) */}
      <div>
        <div className='flex items-center justify-between mb-2'>
          <div className='flex items-center gap-1.5'>
            <span className='w-2 h-2 rounded-full bg-red-500 shrink-0' />
            <h4 className='text-xs font-medium text-slate-500 dark:text-zinc-400 uppercase tracking-wider'>{t('dynamicAirspaces')}</h4>
          </div>
          <button
            onClick={onAupSync}
            disabled={isSyncingAup}
            className='flex items-center gap-1 text-[10px] text-sky-500 hover:text-sky-600 disabled:opacity-50 transition-colors select-none'
          >
            <Navigation className={`h-3 w-3 ${isSyncingAup ? 'animate-spin' : ''}`} />
            {isSyncingAup ? t('aupSyncing') : t('aupSync')}
          </button>
        </div>
        <AirspaceTypeGrid types={DYNAMIC_TYPES} layers={layers} onToggle={onToggleAirspaceType} />
        {aupLastSync && (
          <p className='mt-1.5 text-[10px] text-slate-400 dark:text-zinc-500'>
            {t('aupLastSync')}: {aupLastSync.toLocaleTimeString()}
          </p>
        )}
      </div>

      {/* Static Airspaces */}
      <div>
        <div className='flex items-center gap-1.5 mb-2'>
          <span className='w-2 h-2 rounded-full bg-blue-500 shrink-0' />
          <h4 className='text-xs font-medium text-slate-500 dark:text-zinc-400 uppercase tracking-wider'>{t('staticAirspaces')}</h4>
        </div>
        <AirspaceTypeGrid types={STATIC_TYPES} layers={layers} onToggle={onToggleAirspaceType} />
      </div>

      {/* Other / Informational */}
      <div>
        <div className='flex items-center gap-1.5 mb-2'>
          <span className='w-2 h-2 rounded-full bg-slate-400 shrink-0' />
          <h4 className='text-xs font-medium text-slate-500 dark:text-zinc-400 uppercase tracking-wider'>{t('otherAirspaces')}</h4>
        </div>
        <AirspaceTypeGrid types={OTHER_TYPES} layers={layers} onToggle={onToggleAirspaceType} />
      </div>

      {/* Altitude Range */}
      <div>
        <h4 className='text-xs font-medium text-slate-500 dark:text-zinc-400 uppercase tracking-wider mb-2'>{t('altitudeRange')}</h4>
        <div className='flex items-center gap-2'>
          <span className='text-[10px] text-slate-400 font-mono w-8'>GND</span>
          <input
            type='range'
            min={0}
            max={66000}
            step={500}
            value={layers.altitudeRange[1]}
            onChange={e => onUpdateLayer('altitudeRange', [0, Number(e.target.value)])}
            className='flex-1 accent-sky-500'
          />
          <span className='text-[10px] text-slate-400 font-mono w-14 text-right'>{formatAltFt(layers.altitudeRange[1])}</span>
        </div>
      </div>

      {/* Terrain Overlay */}
      <div>
        <div className='flex items-center justify-between mb-1'>
          <h4 className='flex items-center gap-1.5 text-xs font-medium text-slate-500 dark:text-zinc-400'>
            <Mountain className='h-3 w-3' />
            {t('terrainOverlay')}
          </h4>
          <ToggleSwitch checked={layers.showTerrain} onChange={v => onUpdateLayer('showTerrain', v)} />
        </div>
        {layers.showTerrain && (
          <div className='flex items-center gap-2 mt-1'>
            <span className='text-[10px] text-slate-400'>0%</span>
            <input
              type='range'
              min={0}
              max={80}
              step={5}
              value={layers.terrainOpacity * 100}
              onChange={e => onUpdateLayer('terrainOpacity', Number(e.target.value) / 100)}
              className='flex-1 accent-sky-500'
            />
            <span className='text-[10px] text-slate-400'>{Math.round(layers.terrainOpacity * 100)}%</span>
          </div>
        )}
      </div>

      {/* Object Toggles */}
      <div>
        <h4 className='text-xs font-medium text-slate-500 dark:text-zinc-400 uppercase tracking-wider mb-2'>{t('mapObjects')}</h4>
        <div className='flex flex-col gap-1.5'>
          <ToggleRow icon={PlaneLanding} label={t('airports')} checked={layers.showAirports} onChange={v => onUpdateLayer('showAirports', v)} />
          <ToggleRow icon={SquareDot} label={t('navaids')} checked={layers.showNavaids} onChange={v => onUpdateLayer('showNavaids', v)} />
          <ToggleRow icon={TrafficCone} label={t('obstacles')} checked={layers.showObstacles} onChange={v => onUpdateLayer('showObstacles', v)} />
          <ToggleRow
            icon={Triangle}
            label={t('reportingPoints')}
            checked={layers.showReportingPoints}
            onChange={v => onUpdateLayer('showReportingPoints', v)}
          />
        </div>
      </div>

      {/* Download */}
      <div className='mt-2 pt-2 border-t border-slate-200/80 dark:border-zinc-700/80'>
        <Button variant='outline' size='sm' className='w-full rounded-xl' onClick={onDownload} disabled={isDownloading || isOffline}>
          <Download className='h-4 w-4 mr-2' />
          {isDownloading ? t('downloading') : t('downloadOffline')}
        </Button>
        {lastDownloadDate && (
          <p className='mt-1 text-[10px] text-center text-slate-400 dark:text-zinc-500'>
            {t('lastDownload')}: {new Date(lastDownloadDate).toLocaleDateString()}
          </p>
        )}
      </div>
    </>
  );
}

function ToggleSwitch({ checked, onChange }: { checked: boolean; onChange: (v: boolean) => void }) {
  return (
    <button
      onClick={() => onChange(!checked)}
      className={`relative w-9 h-5 rounded-full transition-colors ${checked ? 'bg-sky-500' : 'bg-slate-300 dark:bg-zinc-600'}`}
    >
      <div className={`absolute top-0.5 left-0.5 w-4 h-4 rounded-full bg-white shadow transition-transform ${checked ? 'translate-x-4' : ''}`} />
    </button>
  );
}

function ToggleRow({ icon: Icon, label, checked, onChange }: { icon: any; label: string; checked: boolean; onChange: (v: boolean) => void }) {
  return (
    <div className='flex items-center justify-between rounded-lg bg-slate-50 dark:bg-zinc-800/70 px-2.5 py-2'>
      <div className='flex items-center gap-2'>
        <Icon className='h-3.5 w-3.5 text-slate-500 dark:text-zinc-400' />
        <span className='text-xs text-slate-700 dark:text-zinc-300'>{label}</span>
      </div>
      <ToggleSwitch checked={checked} onChange={onChange} />
    </div>
  );
}

'use client';

import { useRouter } from 'next/navigation';
import { useLocale, useTranslations } from 'next-intl';
import { useTheme } from 'next-themes';
import { useEffect, useState } from 'react';
import { Sun, Moon, Monitor, SunMoon, Languages, Check } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '@/components/ui/dropdown-menu';
import { setLocale } from '@/lib/locale-actions';

const themes = [
  { value: 'light', icon: Sun },
  { value: 'dark', icon: Moon },
  { value: 'system', icon: Monitor },
] as const;

const locales = [
  { value: 'en', label: 'English' },
  { value: 'pl', label: 'Polski' },
] as const;

export function ThemeDropdown() {
  const { theme, setTheme } = useTheme();
  const th = useTranslations('theme');
  const ti = useTranslations('nav');
  const [mounted, setMounted] = useState(false);

  useEffect(() => setMounted(true), []);

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          variant='ghost'
          size='sm'
          className='h-9 w-9 px-0 text-slate-500 dark:text-zinc-400 hover:text-slate-800 dark:hover:text-zinc-200'
          title={ti('theme')}
        >
          <SunMoon className='h-4.5 w-4.5' />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align='end'>
        {themes.map(({ value, icon: Icon }) => (
          <DropdownMenuItem key={value} onClick={() => setTheme(value)} className='gap-2'>
            <Icon className='h-4 w-4' />
            {th(value as 'light' | 'dark' | 'system')}
            {mounted && theme === value && <Check className='h-3.5 w-3.5 ml-auto text-sky-500' />}
          </DropdownMenuItem>
        ))}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

export function LocaleDropdown() {
  const locale = useLocale();
  const router = useRouter();
  const ti = useTranslations('nav');
  async function handleLocaleChange(newLocale: string) {
    await setLocale(newLocale);
    router.refresh();
  }

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          variant='ghost'
          size='sm'
          className='h-9 w-9 px-0 text-slate-500 dark:text-zinc-400 hover:text-slate-800 dark:hover:text-zinc-200'
          title={ti('language')}
        >
          <Languages className='h-4.5 w-4.5' />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align='end'>
        {locales.map(({ value, label }) => (
          <DropdownMenuItem key={value} onClick={() => handleLocaleChange(value)} className='gap-2'>
            {label}
            {locale === value && <Check className='h-3.5 w-3.5 ml-auto text-sky-500' />}
          </DropdownMenuItem>
        ))}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

'use client';

import Link from 'next/link';
import { ShieldCheck, Settings, HelpCircle, Megaphone, LogOut } from 'lucide-react';
import { useTranslations, useFormatter } from 'next-intl';
import { UserAvatar } from '@/components/user-avatar';
import { ThemeDropdown, LocaleDropdown } from '@/components/nav-dropdowns';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { Tooltip, TooltipContent, TooltipTrigger } from '@/components/ui/tooltip';
import { signOut } from 'next-auth/react';

const GREETING_COUNT = 9;

type NavbarProps = {
  user: {
    id: string;
    firstName: string;
    lastName: string;
    username: string;
    email: string;
    avatarColor: string;
    role: string;
  };
};

export function Navbar({ user }: NavbarProps) {
  const t = useTranslations();
  const format = useFormatter();

  // Deterministic "random" greeting based on user ID to prevent hydration mismatch
  const greetingIndex = user.id ? user.id.charCodeAt(user.id.length - 1) % GREETING_COUNT : 0;

  const isAdmin = user.role === 'ADMIN';

  const navLinks = [
    { icon: Megaphone, label: t('nav.changelog'), href: '/changelog' },
    { icon: HelpCircle, label: t('nav.help'), href: '/manual' },
    { icon: Settings, label: t('nav.settings'), href: '/settings' },
    ...(isAdmin ? [{ icon: ShieldCheck, label: t('nav.admin'), href: '/admin' }] : []),
  ];

  return (
    <header className='sticky top-0 z-50 w-full'>
      <div className='w-full max-w-none rounded-none border-b border-border bg-background'>
        <div className='relative flex h-14 items-center justify-between px-4 lg:px-5'>
          {/* Left — logo */}
          <Link href='/' className='text-lg font-bold tracking-tight text-sky-600 dark:text-sky-400 select-none shrink-0'>
            flyteLog
          </Link>

          {/* Center — greeting */}
          <div className='absolute inset-x-0 hidden md:flex justify-center pointer-events-none px-48'>
            <p className='text-sm text-slate-500 dark:text-zinc-400 truncate'>{t(`greetings.${greetingIndex}`, { name: user.firstName })}</p>
          </div>

          {/* Right — actions */}

          <div className='flex items-center gap-0.5'>
            <ThemeDropdown />
            <LocaleDropdown />

            <div className='w-px h-5 rounded-full border border-slate-500 dark:border-zinc-400 mx-2' />

            {navLinks.map(({ icon: Icon, label, href }) => (
              <Tooltip key={href}>
                <TooltipTrigger asChild>
                  <Button
                    variant='ghost'
                    size='sm'
                    asChild
                    className='h-9 w-9 px-0 text-slate-500 dark:text-zinc-400 hover:text-slate-800 dark:hover:text-zinc-200 hidden sm:inline-flex'
                  >
                    <Link href={href}>
                      <Icon className='h-4.5 w-4.5' />
                    </Link>
                  </Button>
                </TooltipTrigger>
                <TooltipContent>
                  <p>{label}</p>
                </TooltipContent>
              </Tooltip>
            ))}

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant='ghost' size='sm' className='h-9 w-9 px-0 ml-0.5 rounded-full' title={t('nav.account')}>
                  <UserAvatar firstName={user.firstName} lastName={user.lastName} color={user.avatarColor} size='sm' />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent
                align='end'
                className='w-64 p-2 bg-white/75 dark:bg-zinc-900/75 backdrop-blur-lg shadow-lg shadow-slate-200/50 dark:shadow-zinc-950/50 mt-4'
              >
                <DropdownMenuLabel className='font-normal flex flex-col gap-1 p-2'>
                  <div className='flex flex-col space-y-1'>
                    <p className='text-sm font-medium leading-none text-slate-900 dark:text-zinc-100'>
                      {user.firstName} {user.lastName}
                    </p>
                    <p className='text-xs leading-none text-slate-500 dark:text-zinc-400 italic'>{user.username}</p>
                    <p className='text-xs leading-none text-slate-500 dark:text-zinc-400'>{user.email}</p>
                  </div>
                </DropdownMenuLabel>
                <DropdownMenuSeparator />
                <DropdownMenuItem asChild className='cursor-pointer gap-2'>
                  <Link href='/settings'>
                    <Settings className='h-4 w-4 text-slate-500' />
                    {t('nav.accSettings')}
                  </Link>
                </DropdownMenuItem>
                <DropdownMenuItem
                  onClick={() => signOut()}
                  className='cursor-pointer gap-2 text-red-600 dark:text-red-400 focus:text-red-600 dark:focus:text-red-400'
                >
                  <LogOut className='h-4 w-4' />
                  {t('nav.signOut')}
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        </div>
      </div>
    </header>
  );
}

'use client';

import {
  createContext,
  useContext,
  useReducer,
  useMemo,
  useCallback,
  type ReactNode,
} from 'react';
import {
  calculateWCA,
  calculateGroundSpeed,
  calculateMagneticHeading,
  calculateLegTime,
  calculateSunsetUtc,
  calculateFuel,
  calculateMoment,
  sumWBItems,
  fuelLitresToKg,
  type FuelCalculationResult,
  type WBResult,
} from '@/lib/ofp-calculations';
import { db } from '@/lib/dexie/db';

// ── Types ──────────────────────────────────────────────────────────

export type FlightRules = 'VFR' | 'IFR';

export interface RouteLeg {
  waypoint: string;
  distance: number;       // NM (user input)
  magneticTrack: number;  // degrees (user input)
  msa: number;            // ft (user input) — MSA (VFR) or Grid MORA (IFR)
  safeAlt: number;        // ft (user input) — Safe Alt (VFR) or MEA (IFR)
  planAltitude: number;   // ft or FL (user input)
  // Auto-calculated:
  wca: number;
  magneticHeading: number;
  groundSpeed: number;
  legTimeMin: number;
}

export interface RadioFrequency {
  name: string;
  frequency: string;
  checked: boolean;
}

export interface WBRow {
  mass: number;
  arm: number;
}

export interface OfpState {
  // Section 1 — General
  flightDate: string;           // YYYY-MM-DD
  aircraftType: string;
  registration: string;
  departureIcao: string;
  destinationIcao: string;
  sunsetUtc: string;            // HH:MM
  sunsetManual: boolean;
  flightRules: FlightRules;
  task: string;
  edt: string;                  // HH:MM
  ato: string;
  eta: string;
  ata: string;

  // Section 2 — Passengers
  pic: string;
  crewFunction: string;
  personsOnBoard: number;

  // Section 3 — Weather minima
  visibility: number;           // m
  cloudCeiling: number;         // ft
  windCrosswind: number;        // kt
  windTotal: number;            // kt
  temperature: number;          // °C

  // Section 4 — Weather calc
  tas: number;                  // kt
  windDirection: number;        // degrees
  windSpeed: number;            // kt

  // Section 5 — Route
  routeLegs: RouteLeg[];

  // Section 6 — Alternate
  alternateLegs: RouteLeg[];

  // Section 7 — Radio
  radioFrequencies: RadioFrequency[];

  // Section 8 — Fuel
  fuelBurnLph: number;          // L/h
  taxiTimeMin: number;
  finalReserveMin: number;
  additionalFuelLtr: number;
  blockFuelLtr: number;

  // Section 9 — W&B
  bem: WBRow;
  frontSeats: WBRow;
  rearSeats: WBRow;
  baggage: WBRow;

  // Internal — destination coords for sunset calc
  _destLat: number | null;
  _destLon: number | null;
}

// ── Default State ──────────────────────────────────────────────────

const createEmptyLeg = (): RouteLeg => ({
  waypoint: '',
  distance: 0,
  magneticTrack: 0,
  msa: 0,
  safeAlt: 0,
  planAltitude: 0,
  wca: 0,
  magneticHeading: 0,
  groundSpeed: 0,
  legTimeMin: 0,
});

const createEmptyFrequency = (): RadioFrequency => ({
  name: '',
  frequency: '',
  checked: false,
});

export const initialOfpState: OfpState = {
  flightDate: new Date().toISOString().slice(0, 10),
  aircraftType: '',
  registration: '',
  departureIcao: '',
  destinationIcao: '',
  sunsetUtc: '',
  sunsetManual: false,
  flightRules: 'VFR',
  task: '',
  edt: '',
  ato: '',
  eta: '',
  ata: '',

  pic: '',
  crewFunction: '',
  personsOnBoard: 1,

  visibility: 0,
  cloudCeiling: 0,
  windCrosswind: 0,
  windTotal: 0,
  temperature: 0,

  tas: 0,
  windDirection: 0,
  windSpeed: 0,

  routeLegs: [createEmptyLeg(), createEmptyLeg()],
  alternateLegs: [createEmptyLeg()],

  radioFrequencies: Array.from({ length: 6 }, createEmptyFrequency),

  fuelBurnLph: 0,
  taxiTimeMin: 0,
  finalReserveMin: 45,
  additionalFuelLtr: 0,
  blockFuelLtr: 0,

  bem: { mass: 0, arm: 0 },
  frontSeats: { mass: 0, arm: 0 },
  rearSeats: { mass: 0, arm: 0 },
  baggage: { mass: 0, arm: 0 },

  _destLat: null,
  _destLon: null,
};

// ── Actions ────────────────────────────────────────────────────────

type OfpAction =
  | { type: 'SET_FIELD'; field: keyof OfpState; value: unknown }
  | { type: 'SET_ROUTE_LEG'; index: number; field: keyof RouteLeg; value: number | string }
  | { type: 'ADD_ROUTE_LEG' }
  | { type: 'REMOVE_ROUTE_LEG'; index: number }
  | { type: 'SET_ALT_LEG'; index: number; field: keyof RouteLeg; value: number | string }
  | { type: 'ADD_ALT_LEG' }
  | { type: 'REMOVE_ALT_LEG'; index: number }
  | { type: 'SET_RADIO'; index: number; field: keyof RadioFrequency; value: string | boolean }
  | { type: 'SET_WB'; category: 'bem' | 'frontSeats' | 'rearSeats' | 'baggage'; field: 'mass' | 'arm'; value: number }
  | { type: 'SET_DEST_COORDS'; lat: number; lon: number }
  | { type: 'SET_SUNSET'; value: string };

function recalculateLegs(legs: RouteLeg[], tas: number, windSpeed: number, windDirection: number): RouteLeg[] {
  return legs.map(leg => {
    if (leg.distance <= 0 || leg.magneticTrack <= 0) return leg;

    const wca = calculateWCA(tas, windSpeed, windDirection, leg.magneticTrack);
    const groundSpeed = calculateGroundSpeed(tas, windSpeed, windDirection, leg.magneticTrack);
    const magneticHeading = calculateMagneticHeading(leg.magneticTrack, wca);
    const legTimeMin = calculateLegTime(leg.distance, groundSpeed);

    return { ...leg, wca, magneticHeading, groundSpeed, legTimeMin };
  });
}

function ofpReducer(state: OfpState, action: OfpAction): OfpState {
  switch (action.type) {
    case 'SET_FIELD': {
      const newState = { ...state, [action.field]: action.value };

      // Recalculate legs when wind/TAS change
      if (action.field === 'tas' || action.field === 'windSpeed' || action.field === 'windDirection') {
        newState.routeLegs = recalculateLegs(newState.routeLegs, newState.tas, newState.windSpeed, newState.windDirection);
        newState.alternateLegs = recalculateLegs(newState.alternateLegs, newState.tas, newState.windSpeed, newState.windDirection);
      }

      return newState;
    }

    case 'SET_ROUTE_LEG': {
      const legs = [...state.routeLegs];
      legs[action.index] = { ...legs[action.index], [action.field]: action.value };

      // Recalculate this leg
      const leg = legs[action.index];
      if (leg.distance > 0 && leg.magneticTrack > 0 && state.tas > 0) {
        leg.wca = calculateWCA(state.tas, state.windSpeed, state.windDirection, leg.magneticTrack);
        leg.groundSpeed = calculateGroundSpeed(state.tas, state.windSpeed, state.windDirection, leg.magneticTrack);
        leg.magneticHeading = calculateMagneticHeading(leg.magneticTrack, leg.wca);
        leg.legTimeMin = calculateLegTime(leg.distance, leg.groundSpeed);
      }

      return { ...state, routeLegs: legs };
    }

    case 'ADD_ROUTE_LEG': {
      if (state.routeLegs.length >= 19) return state;
      return { ...state, routeLegs: [...state.routeLegs, createEmptyLeg()] };
    }

    case 'REMOVE_ROUTE_LEG': {
      if (state.routeLegs.length <= 1) return state;
      return { ...state, routeLegs: state.routeLegs.filter((_, i) => i !== action.index) };
    }

    case 'SET_ALT_LEG': {
      const legs = [...state.alternateLegs];
      legs[action.index] = { ...legs[action.index], [action.field]: action.value };

      const leg = legs[action.index];
      if (leg.distance > 0 && leg.magneticTrack > 0 && state.tas > 0) {
        leg.wca = calculateWCA(state.tas, state.windSpeed, state.windDirection, leg.magneticTrack);
        leg.groundSpeed = calculateGroundSpeed(state.tas, state.windSpeed, state.windDirection, leg.magneticTrack);
        leg.magneticHeading = calculateMagneticHeading(leg.magneticTrack, leg.wca);
        leg.legTimeMin = calculateLegTime(leg.distance, leg.groundSpeed);
      }

      return { ...state, alternateLegs: legs };
    }

    case 'ADD_ALT_LEG': {
      if (state.alternateLegs.length >= 5) return state;
      return { ...state, alternateLegs: [...state.alternateLegs, createEmptyLeg()] };
    }

    case 'REMOVE_ALT_LEG': {
      if (state.alternateLegs.length <= 1) return state;
      return { ...state, alternateLegs: state.alternateLegs.filter((_, i) => i !== action.index) };
    }

    case 'SET_RADIO': {
      const freqs = [...state.radioFrequencies];
      freqs[action.index] = { ...freqs[action.index], [action.field]: action.value };
      return { ...state, radioFrequencies: freqs };
    }

    case 'SET_WB': {
      return {
        ...state,
        [action.category]: {
          ...state[action.category],
          [action.field]: action.value,
        },
      };
    }

    case 'SET_DEST_COORDS':
      return { ...state, _destLat: action.lat, _destLon: action.lon };

    case 'SET_SUNSET':
      return { ...state, sunsetUtc: action.value };

    default:
      return state;
  }
}

// ── Derived Values ─────────────────────────────────────────────────

function useDerivedFuel(state: OfpState): FuelCalculationResult {
  return useMemo(() => {
    const cruiseTimeMin = state.routeLegs.reduce((sum, l) => sum + l.legTimeMin, 0);
    const alternateTimeMin = state.alternateLegs.reduce((sum, l) => sum + l.legTimeMin, 0);

    return calculateFuel({
      fuelBurnLph: state.fuelBurnLph,
      taxiTimeMin: state.taxiTimeMin,
      cruiseTimeMin,
      alternateTimeMin,
      finalReserveMin: state.finalReserveMin,
      additionalLtr: state.additionalFuelLtr,
      blockFuelLtr: state.blockFuelLtr,
    });
  }, [
    state.fuelBurnLph, state.taxiTimeMin, state.routeLegs,
    state.alternateLegs, state.finalReserveMin,
    state.additionalFuelLtr, state.blockFuelLtr,
  ]);
}

function useDerivedWB(state: OfpState, fuel: FuelCalculationResult) {
  return useMemo(() => {
    const bemResult = calculateMoment(state.bem);
    const frontResult = calculateMoment(state.frontSeats);
    const rearResult = calculateMoment(state.rearSeats);
    const baggageResult = calculateMoment(state.baggage);
    const zfm = sumWBItems([bemResult, frontResult, rearResult, baggageResult]);

    // Trip fuel = (block - taxi) in litres → to kg
    const tripFuelLtr = Math.max(0, state.blockFuelLtr - fuel.taxiFuelLtr);
    const tripFuelKg = fuelLitresToKg(tripFuelLtr);
    const tripFuelResult = calculateMoment({ mass: tripFuelKg, arm: state.bem.arm });

    const takeoffMass = sumWBItems([zfm, tripFuelResult]);

    // Landing fuel
    const landingFuelLtr = Math.max(0, state.blockFuelLtr - fuel.taxiFuelLtr - fuel.cruiseFuelLtr);
    const landingFuelKg = fuelLitresToKg(landingFuelLtr);
    const landingFuelResult = calculateMoment({ mass: landingFuelKg, arm: state.bem.arm });
    const landingMass = sumWBItems([zfm, landingFuelResult]);

    // Alternate landing fuel
    const altFuelLtr = Math.max(0, state.blockFuelLtr - fuel.taxiFuelLtr - fuel.cruiseFuelLtr - fuel.alternateFuelLtr);
    const altFuelKg = fuelLitresToKg(altFuelLtr);
    const altFuelResult = calculateMoment({ mass: altFuelKg, arm: state.bem.arm });
    const altMass = sumWBItems([zfm, altFuelResult]);

    return {
      bem: bemResult,
      frontSeats: frontResult,
      rearSeats: rearResult,
      baggage: baggageResult,
      zfm,
      tripFuel: { ...tripFuelResult, litres: tripFuelLtr },
      takeoffMass,
      landingFuel: { ...landingFuelResult, litres: landingFuelLtr },
      landingMass,
      altFuel: { ...altFuelResult, litres: altFuelLtr },
      altMass,
    };
  }, [state.bem, state.frontSeats, state.rearSeats, state.baggage, state.blockFuelLtr, fuel]);
}

// ── Context ────────────────────────────────────────────────────────

interface OfpContextValue {
  state: OfpState;
  dispatch: React.Dispatch<OfpAction>;
  fuel: FuelCalculationResult;
  wb: ReturnType<typeof useDerivedWB>;
  routeTotals: { distance: number; time: number };
  altTotals: { distance: number; time: number };
  lookupAirport: (icao: string) => Promise<{ lat: number; lon: number; name: string } | null>;
}

const OfpContext = createContext<OfpContextValue | null>(null);

export function OfpProvider({ children }: { children: ReactNode }) {
  const [state, dispatch] = useReducer(ofpReducer, initialOfpState);

  const fuel = useDerivedFuel(state);
  const wb = useDerivedWB(state, fuel);

  const routeTotals = useMemo(() => ({
    distance: state.routeLegs.reduce((s, l) => s + l.distance, 0),
    time: state.routeLegs.reduce((s, l) => s + l.legTimeMin, 0),
  }), [state.routeLegs]);

  const altTotals = useMemo(() => ({
    distance: state.alternateLegs.reduce((s, l) => s + l.distance, 0),
    time: state.alternateLegs.reduce((s, l) => s + l.legTimeMin, 0),
  }), [state.alternateLegs]);

  const lookupAirport = useCallback(async (icao: string) => {
    if (!icao || icao.length < 2) return null;
    const airport = await db.airports
      .where('icaoCode')
      .equalsIgnoreCase(icao)
      .first();
    if (!airport) return null;
    return { lat: airport.lat, lon: airport.lon, name: airport.name };
  }, []);

  const value = useMemo<OfpContextValue>(
    () => ({ state, dispatch, fuel, wb, routeTotals, altTotals, lookupAirport }),
    [state, dispatch, fuel, wb, routeTotals, altTotals, lookupAirport],
  );

  return (
    <OfpContext.Provider value={value}>
      {children}
    </OfpContext.Provider>
  );
}

export function useOfp() {
  const ctx = useContext(OfpContext);
  if (!ctx) throw new Error('useOfp must be used within OfpProvider');
  return ctx;
}

export { calculateSunsetUtc };

'use client';

import { useCallback } from 'react';
import { useTranslations } from 'next-intl';
import { useOfp, type OfpState } from '@/components/ofp/ofp-context';
import { formatMinutesAsTime } from '@/lib/ofp-calculations';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';

export function FuelCalc() {
  const t = useTranslations('ofp');
  const { state, dispatch, fuel } = useOfp();

  const setField = useCallback(
    (field: string, value: unknown) => dispatch({ type: 'SET_FIELD', field: field as never, value }),
    [dispatch],
  );

  const getEditableValue = (field: string): number => {
    const editableFields: Record<string, number> = {
      fuelBurnLph: state.fuelBurnLph,
      taxiTimeMin: state.taxiTimeMin,
      finalReserveMin: state.finalReserveMin,
      additionalFuelLtr: state.additionalFuelLtr,
      blockFuelLtr: state.blockFuelLtr,
    };
    return editableFields[field] ?? 0;
  };

  const rows: {
    label: string;
    time: number;
    fuelLtr: number;
    editable?: { timeField?: string; fuelField?: string };
    highlight?: boolean;
  }[] = [
    {
      label: t('fuelBurnRate'),
      time: 0,
      fuelLtr: state.fuelBurnLph,
      editable: { fuelField: 'fuelBurnLph' },
    },
    {
      label: t('taxi'),
      time: fuel.taxiTimeMin,
      fuelLtr: fuel.taxiFuelLtr,
      editable: { timeField: 'taxiTimeMin' },
    },
    {
      label: t('cruise'),
      time: fuel.cruiseTimeMin,
      fuelLtr: fuel.cruiseFuelLtr,
    },
    {
      label: `${t('contingency')} (5%)`,
      time: fuel.contingencyTimeMin,
      fuelLtr: fuel.contingencyFuelLtr,
    },
    {
      label: t('alternate'),
      time: fuel.alternateTimeMin,
      fuelLtr: fuel.alternateFuelLtr,
    },
    {
      label: t('finalReserve'),
      time: fuel.finalReserveMin,
      fuelLtr: fuel.finalReserveFuelLtr,
      editable: { timeField: 'finalReserveMin' },
    },
    {
      label: t('additional'),
      time: fuel.additionalTimeMin,
      fuelLtr: fuel.additionalFuelLtr,
      editable: { fuelField: 'additionalFuelLtr' },
    },
    {
      label: t('required'),
      time: fuel.requiredTimeMin,
      fuelLtr: fuel.requiredFuelLtr,
      highlight: true,
    },
    {
      label: t('extra'),
      time: fuel.extraTimeMin,
      fuelLtr: fuel.extraFuelLtr,
    },
    {
      label: t('block'),
      time: fuel.blockTimeMin,
      fuelLtr: fuel.blockFuelLtr,
      editable: { fuelField: 'blockFuelLtr' },
      highlight: true,
    },
    {
      label: t('safeEndurance'),
      time: fuel.safeEnduranceMin,
      fuelLtr: fuel.safeEnduranceLtr,
      highlight: true,
    },
  ];

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-base">{t('fuelCalc')}</CardTitle>
      </CardHeader>
      <CardContent className="overflow-x-auto -mx-6 px-6">
        <table className="w-full text-sm">
          <thead>
            <tr className="border-b text-left text-xs text-muted-foreground">
              <th className="pb-2 pr-4 font-medium" />
              <th className="pb-2 pr-4 font-medium text-right">{t('time')}</th>
              <th className="pb-2 font-medium text-right">{t('fuelLtr')}</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((row, i) => (
              <tr
                key={i}
                className={`border-b border-border/50 ${row.highlight ? 'bg-sky-500/5 font-medium' : ''}`}
              >
                <td className="py-2 pr-4 text-slate-700 dark:text-zinc-300 whitespace-nowrap">
                  {row.label}
                </td>
                <td className="py-2 pr-4 text-right tabular-nums">
                  {row.editable?.timeField ? (
                    <Input
                      className="h-8 w-20 text-right text-sm tabular-nums ml-auto"
                      type="number"
                      min={0}
                      value={getEditableValue(row.editable.timeField) || ''}
                      onChange={e => setField(row.editable!.timeField!, parseFloat(e.target.value) || 0)}
                    />
                  ) : (
                    <span className="text-muted-foreground">
                      {row.time > 0 ? formatMinutesAsTime(row.time) : '—'}
                    </span>
                  )}
                </td>
                <td className="py-2 text-right tabular-nums">
                  {row.editable?.fuelField ? (
                    <Input
                      className="h-8 w-24 text-right text-sm tabular-nums ml-auto"
                      type="number"
                      min={0}
                      step={0.1}
                      value={getEditableValue(row.editable.fuelField) || ''}
                      onChange={e => setField(row.editable!.fuelField!, parseFloat(e.target.value) || 0)}
                    />
                  ) : (
                    <span className="text-muted-foreground">
                      {row.fuelLtr > 0 ? row.fuelLtr.toFixed(1) : '—'}
                    </span>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </CardContent>
    </Card>
  );
}

