'use client';

import { useEffect, useState, useRef, useCallback, useMemo } from 'react';
import { MapContainer, TileLayer, Marker, Popup, Polyline, GeoJSON, ImageOverlay, useMap, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import { LocateFixed, Map, Globe, Triangle, SquareDot, TrafficCone, Locate, PlaneTakeoff, MapPin, X, Info, Crosshair, PlaneLanding } from 'lucide-react';
import { renderToStaticMarkup } from 'react-dom/server';
import { useTranslations } from 'next-intl';
import { useRoute, type Waypoint } from '@/components/route/route-context';
import type { LayerState } from '@/components/map-sidebar';
import type { WarningLevel } from '@/lib/navlog';
import { computeNavlog, type NavlogEntry } from '@/lib/navlog';
import { getTerrainProfile } from '@/lib/terrain';

delete (L.Icon.Default.prototype as any)._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

function createWaypointIcon(index: number, role: string) {
  const bg = role === 'departure' ? '#22c55e' : role === 'destination' ? '#ef4444' : '#3b82f6';
  const label = role === 'departure' ? 'D' : role === 'destination' ? 'A' : String(index + 1);
  return L.divIcon({
    className: '',
    html: `<div style="width:28px;height:28px;border-radius:50%;background:${bg};border:3px solid white;box-shadow:0 2px 8px rgba(0,0,0,0.3);display:flex;align-items:center;justify-content:center;color:white;font-size:11px;font-weight:700;">${label}</div>`,
    iconSize: [28, 28],
    iconAnchor: [14, 14],
  });
}

// Lucide icon SVGs pre-rendered for Leaflet divIcons
const LUCIDE_ICONS = {
  airport: renderToStaticMarkup(<Locate width={22} height={22} stroke='#6b7280' strokeWidth={1.75} fill='none' />),
  navaid: renderToStaticMarkup(<SquareDot width={20} height={20} stroke='#8b5cf6' strokeWidth={1.75} fill='none' />),
  obstacle: renderToStaticMarkup(<TrafficCone width={18} height={18} stroke='#ef4444' strokeWidth={1.75} fill='none' />),
  'reporting-point': renderToStaticMarkup(<Triangle width={20} height={20} stroke='#3b82f6' strokeWidth={1.75} fill='none' />),
} as const;

const ICON_SIZES: Record<string, number> = {
  airport: 22,
  navaid: 20,
  obstacle: 18,
  'reporting-point': 20,
};

function createObjectIcon(type: 'airport' | 'navaid' | 'obstacle' | 'reporting-point') {
  const svg = LUCIDE_ICONS[type];
  const size = ICON_SIZES[type] ?? 20;
  return L.divIcon({
    className: '',
    html: `<div style="filter:drop-shadow(0 1px 3px rgba(0,0,0,0.4));display:flex;align-items:center;justify-content:center;">${svg}</div>`,
    iconSize: [size, size],
    iconAnchor: [size / 2, size / 2],
  });
}

const LEG_COLORS: Record<WarningLevel, string> = {
  safe: '#22c55e',
  warning: '#f59e0b',
  danger: '#ef4444',
};

function createLegInfoIcon(magneticTrack: number, distanceNM: number, warningLevel: WarningLevel) {
  const bg = warningLevel === 'danger' ? 'rgba(239,68,68,0.9)' : warningLevel === 'warning' ? 'rgba(245,158,11,0.9)' : 'rgba(255,255,255,0.92)';
  const color = warningLevel === 'safe' ? '#374151' : '#ffffff';
  return L.divIcon({
    className: '',
    html: `<div style="background:${bg};backdrop-filter:blur(8px);padding:2px 8px;border-radius:8px;font-size:10px;font-weight:600;color:${color};white-space:nowrap;box-shadow:0 1px 4px rgba(0,0,0,0.15);border:1px solid rgba(255,255,255,0.3);pointer-events:none;">${magneticTrack}° · ${distanceNM} NM</div>`,
    iconSize: [0, 0],
    iconAnchor: [0, 10],
  });
}

const DEFAULT_CENTER: [number, number] = [50.11, 22.019];
const DEFAULT_ZOOM = 7;

// OpenAIP type → colour — must mirror DYNAMIC_TYPES / STATIC_TYPES / OTHER_TYPES in map-sidebar.tsx
const AIRSPACE_COLORS: Record<number, string> = {
  1: '#dc2626', // R     — dark red
  2: '#a855f7', // D     — purple
  3: '#7f1d1d', // P     — maroon
  4: '#3b82f6', // CTR   — blue
  5: '#818cf8', // TMZ   — indigo-light
  6: '#94a3b8', // RMZ   — slate
  7: '#0ea5e9', // TMA   — sky
  8: '#f97316', // TRA   — orange
  9: '#ef4444', // TSA   — red
  13: '#22c55e', // ATZ   — green
  18: '#f59e0b', // BVLOS — amber
  21: '#84cc16', // LFA   — lime
  28: '#ec4899', // SPORT — pink
  30: '#6366f1', // MRT   — indigo
  33: '#64748b', // NPZ   — slate
};

function getAirspaceColor(type: number) {
  return AIRSPACE_COLORS[type] || '#6b7280';
}

// Poland terrain tile bounds (N49-N54, E014-E023)
const TERRAIN_TILES: { key: string; bounds: [[number, number], [number, number]] }[] = [];
for (let lat = 49; lat <= 54; lat++) {
  for (let lon = 14; lon <= 23; lon++) {
    const ns = lat >= 0 ? 'N' : 'S';
    const ew = lon >= 0 ? 'E' : 'W';
    const key = `${ns}${String(Math.abs(lat)).padStart(2, '0')}${ew}${String(Math.abs(lon)).padStart(3, '0')}`;
    TERRAIN_TILES.push({
      key,
      bounds: [
        [lat, lon],
        [lat + 1, lon + 1],
      ],
    });
  }
}

interface AirspaceFeature {
  type: number;
  icaoClass?: number;
  name: string;
  geometry: any;
  upperLimit?: number;
  lowerLimit?: number;
}

interface ObjectRecord {
  name?: string;
  lat: number;
  lon: number;
  icaoCode?: string;
  identifier?: string;
  elevation?: number;
  heightAgl?: number;
  type?: number;
  frequency?: string;
  frequencies?: any[];
  runways?: any[];
  private?: boolean;
  skydiveActivity?: boolean;
  winchOnly?: boolean;
  ppr?: boolean;
  channel?: string;
  range?: number;
  objectKind?: 'airport' | 'navaid' | 'obstacle' | 'reporting-point';
}

interface SelectedPoint {
  lat: number;
  lon: number;
  data: ObjectRecord;
  kind: 'airport' | 'navaid' | 'obstacle' | 'reporting-point';
}

const NAVAID_TYPE_LABELS: Record<number, string> = {
  2: 'VOR',
  3: 'DME',
  4: 'NDB',
  5: 'TACAN',
  6: 'VOR/DME',
  7: 'NDB/DME',
  9: 'ILS',
  10: 'ILS/DME',
  12: 'LOC',
  13: 'LOC/DME',
  14: 'DVOR',
  15: 'DVOR/DME',
};

const AIRPORT_TYPE_LABELS: Record<number, string> = {
  0: 'Civil & Military Airport',
  1: 'Glider Site',
  2: 'Civil Airport',
  3: 'Intl. Airport',
  4: 'Military Heliport',
  5: 'Military Airport',
  6: 'Ultralight Airfield',
  7: 'Civil Heliport',
  8: 'Closed Airfield',
  9: 'Intl. Airport',
  10: 'Water Airfield',
  11: 'Landing Strip',
  12: 'Agricultural Airfield',
  13: 'Mountain Airfield',
};

const POPUP_W = 240;
const POPUP_H_EST = 280;

function PointPopup({
  point,
  popupRef,
  beakRef,
  onClose,
  onAdep,
  onAdes,
  onWpt,
}: {
  point: SelectedPoint;
  popupRef: React.RefObject<HTMLDivElement | null>;
  beakRef: React.RefObject<HTMLDivElement | null>;
  onClose: () => void;
  onAdep: (p: SelectedPoint) => void;
  onAdes: (p: SelectedPoint) => void;
  onWpt: (p: SelectedPoint) => void;
}) {
  const { data, kind } = point;

  const kindColors: Record<SelectedPoint['kind'], string> = {
    airport: '#6b7280',
    navaid: '#8b5cf6',
    obstacle: '#ef4444',
    'reporting-point': '#3b82f6',
  };

  const kindLabel: Record<SelectedPoint['kind'], string> = {
    airport: 'Lotnisko',
    navaid: 'Navaid',
    obstacle: 'Przeszkoda',
    'reporting-point': 'Punkt VFR',
  };

  const typeLabel =
    kind === 'navaid' && data.type != null
      ? (NAVAID_TYPE_LABELS[data.type] ?? `Type ${data.type}`)
      : kind === 'airport' && data.type != null
        ? (AIRPORT_TYPE_LABELS[data.type] ?? `Type ${data.type}`)
        : kindLabel[kind];

  const isAirport = kind === 'airport';

  // Start off-screen; DomPopupTracker repositions via DOM directly
  return (
    <div ref={popupRef} style={{ left: -9999, top: -9999, width: POPUP_W }} className='absolute z-1000 overflow-visible select-none pointer-events-none'>
      {/* Card */}
      <div
        className='rounded-2xl bg-white/95 dark:bg-zinc-900/95 backdrop-blur-xl shadow-2xl overflow-hidden pointer-events-auto'
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className='flex items-start justify-between gap-2 px-3 pt-3 pb-2'>
          <div className='flex-1 min-w-0'>
            <p className='text-sm font-bold text-slate-900 dark:text-zinc-100 leading-tight truncate'>{data.name ?? '—'}</p>
            {(data.icaoCode || data.identifier) && (
              <p className='text-[11px] font-mono text-slate-400 dark:text-zinc-500 mt-0.5'>{data.icaoCode || data.identifier}</p>
            )}
          </div>
          <button
            onClick={onClose}
            className='shrink-0 h-6 w-6 flex items-center justify-center rounded-lg hover:bg-slate-100 dark:hover:bg-zinc-800 transition-colors'
          >
            <X className='h-3.5 w-3.5 text-slate-500' />
          </button>
        </div>

        {/* Type badge */}
        <div className='px-3 pb-2 flex flex-wrap gap-1'>
          <span
            className='inline-flex items-center gap-1 text-[10px] font-semibold uppercase px-2 py-0.5 rounded-full text-white shrink-0'
            style={{ background: kindColors[kind] }}
          >
            <Info className='h-2.5 w-2.5' />
            {typeLabel}
          </span>
          {isAirport && data.private && (
            <span className='inline-flex items-center gap-1 text-[10px] font-semibold uppercase px-2 py-0.5 rounded-full bg-slate-500 text-white shrink-0'>
              Private
            </span>
          )}
          {isAirport && data.ppr && (
            <span className='inline-flex items-center gap-1 text-[10px] font-semibold uppercase px-2 py-0.5 rounded-full bg-amber-500 text-white shrink-0'>
              PPR
            </span>
          )}
          {isAirport && data.skydiveActivity && (
            <span className='inline-flex items-center gap-1 text-[10px] font-semibold uppercase px-2 py-0.5 rounded-full bg-indigo-500 text-white shrink-0'>
              Skydive
            </span>
          )}
          {isAirport && data.winchOnly && (
            <span className='inline-flex items-center gap-1 text-[10px] font-semibold uppercase px-2 py-0.5 rounded-full bg-teal-500 text-white shrink-0'>
              Winch
            </span>
          )}
        </div>

        {/* Data rows */}
        <div className='px-3 pb-2 flex flex-col gap-0.5 max-h-48 overflow-y-auto no-scrollbar'>
          {data.elevation != null && (
            <div className='flex justify-between text-xs'>
              <span className='text-slate-500 dark:text-zinc-400'>AMSL</span>
              <span className='font-medium text-slate-800 dark:text-zinc-200'>{Math.round(data.elevation)} ft</span>
            </div>
          )}
          {data.heightAgl != null && (
            <div className='flex justify-between text-xs'>
              <span className='text-slate-500 dark:text-zinc-400'>AGL</span>
              <span className='font-medium text-slate-800 dark:text-zinc-200'>{Math.round(data.heightAgl)} ft</span>
            </div>
          )}
          {data.frequency && (
            <div className='flex justify-between text-xs'>
              <span className='text-slate-500 dark:text-zinc-400'>FREQ</span>
              <span className='font-medium font-mono text-slate-800 dark:text-zinc-200'>{data.frequency}</span>
            </div>
          )}
          {kind === 'navaid' && data.channel && (
            <div className='flex justify-between text-xs'>
              <span className='text-slate-500 dark:text-zinc-400'>CH</span>
              <span className='font-medium font-mono text-slate-800 dark:text-zinc-200'>{data.channel}</span>
            </div>
          )}
          {kind === 'navaid' && data.range != null && (
            <div className='flex justify-between text-xs'>
              <span className='text-slate-500 dark:text-zinc-400'>RNG</span>
              <span className='font-medium text-slate-800 dark:text-zinc-200'>{data.range} NM</span>
            </div>
          )}
          {isAirport && Array.isArray(data.frequencies) && data.frequencies.length > 0 && (
            <div className='mt-1 flex flex-col gap-0.5 border-t border-slate-100 dark:border-zinc-800 pt-1'>
              {data.frequencies.slice(0, 4).map((f, i) => (
                <div key={`f-${i}`} className='flex justify-between text-xs items-center gap-2'>
                  <span className='text-slate-500 dark:text-zinc-400 truncate uppercase text-[10px]'>{f.name || 'FREQ'}</span>
                  <span className='font-medium font-mono text-slate-800 dark:text-zinc-200 shrink-0'>{f.value}</span>
                </div>
              ))}
            </div>
          )}
          {isAirport && Array.isArray(data.runways) && data.runways.length > 0 && (
            <div className='mt-1 flex flex-col gap-0.5 border-t border-slate-100 dark:border-zinc-800 pt-2 pb-1'>
              {data.runways.map((r, i) => {
                const length = r.dimension?.length?.value;
                return (
                  <div key={`r-${i}`} className='flex justify-between items-center text-xs'>
                    <span className='font-semibold text-slate-700 dark:text-zinc-300'>RWY {r.designator}</span>
                    {length && (
                      <span className='font-medium text-slate-500 dark:text-zinc-400 text-[10px] bg-slate-100 dark:bg-zinc-800 px-1.5 py-0.5 rounded'>
                        {Math.round(length)}m
                      </span>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Action buttons */}
        <div className='flex gap-1 px-3 pb-3'>
          {isAirport && (
            <button
              onClick={() => onAdep(point)}
              className='flex-1 flex flex-col items-center gap-0.5 rounded-xl bg-sky-50 dark:bg-sky-500/10 hover:bg-sky-100 dark:hover:bg-sky-500/20 py-2 transition-colors'
            >
              <PlaneTakeoff className='h-4 w-4 text-sky-500' />
              <span className='text-[9px] font-bold uppercase text-sky-600 dark:text-sky-400'>ADEP</span>
            </button>
          )}
          <button
            onClick={() => onWpt(point)}
            className='flex-1 flex flex-col items-center gap-0.5 rounded-xl bg-sky-50 dark:bg-sky-500/10 hover:bg-sky-100 dark:hover:bg-sky-500/20 py-2 transition-colors'
          >
            <MapPin className='h-4 w-4 text-sky-500' />
            <span className='text-[9px] font-bold uppercase text-sky-600 dark:text-sky-400'>WPT</span>
          </button>
          {isAirport && (
            <button
              onClick={() => onAdes(point)}
              className='flex-1 flex flex-col items-center gap-0.5 rounded-xl bg-sky-50 dark:bg-sky-500/10 hover:bg-sky-100 dark:hover:bg-sky-500/20 py-2 transition-colors'
            >
              <PlaneLanding className='h-4 w-4 text-sky-500' />
              <span className='text-[9px] font-bold uppercase text-sky-600 dark:text-sky-400'>ADES</span>
            </button>
          )}
        </div>
      </div>

      {/* Beak arrow — repositioned by DomPopupTracker via ref */}
      <div
        ref={beakRef}
        style={{ left: POPUP_W / 2 }}
        className='absolute -translate-x-1/2 w-3 h-3 rotate-45 bg-white/95 dark:bg-zinc-900/95 shadow-sm pointer-events-none -bottom-1.5 -z-10'
      />
    </div>
  );
}

/**
 * Lives inside MapContainer — updates popup DOM node position directly
 * on every map move/zoom frame, with zero React re-renders.
 */
function DomPopupTracker({
  latLon,
  popupRef,
  beakRef,
}: {
  latLon: [number, number];
  popupRef: React.RefObject<HTMLDivElement | null>;
  beakRef: React.RefObject<HTMLDivElement | null>;
}) {
  const map = useMap();

  const reposition = useCallback(() => {
    const el = popupRef.current;
    const beak = beakRef.current;
    if (!el) return;

    const pt = map.latLngToContainerPoint(L.latLng(latLon[0], latLon[1]));
    const GAP = 10;
    const BEAK_H = 6;
    const vw = map.getContainer().clientWidth;

    const rawLeft = pt.x - POPUP_W / 2;
    const left = Math.max(8, Math.min(rawLeft, vw - POPUP_W - 8));
    const beakOffset = Math.max(16, Math.min(pt.x - left, POPUP_W - 16));

    const showAbove = pt.y - GAP - BEAK_H >= POPUP_H_EST + 8;
    const top = showAbove ? pt.y - POPUP_H_EST - BEAK_H - GAP : pt.y + GAP;

    el.style.left = `${left}px`;
    el.style.top = `${top}px`;

    if (beak) {
      beak.style.left = `${beakOffset}px`;
      beak.classList.remove('-bottom-1.5', 'border-r', 'border-b', '-top-1.5', 'border-l', 'border-t');
      if (showAbove) {
        beak.classList.add('-bottom-1.5', 'border-r', 'border-b');
      } else {
        beak.classList.add('-top-1.5', 'border-l', 'border-t');
      }
    }
  }, [map, latLon, popupRef, beakRef]);

  useEffect(() => {
    reposition();
  }, [reposition]);

  useMapEvents({ move: reposition, zoom: reposition, viewreset: reposition });

  return null;
}

function MapClickHandler({ onMapClick, onClosePopup }: { onMapClick: (lat: number, lon: number) => void; onClosePopup: () => void }) {
  useMapEvents({
    click(e) {
      const { lat, lng } = e.latlng;
      onClosePopup();
      // Only trigger within Poland bounds
      if (lat >= 49 && lat <= 55 && lng >= 14 && lng <= 24.5) {
        onMapClick(lat, lng);
      }
    },
  });
  return null;
}

function UserLocationUpdater({ center }: { center: [number, number] | null }) {
  const map = useMap();
  useEffect(() => {
    if (center) map.flyTo(center, 13, { duration: 1.5 });
  }, [center, map]);
  return null;
}

interface WorldMapProps {
  airspaces?: AirspaceFeature[];
  layers?: LayerState | null;
  airports?: ObjectRecord[];
  navaids?: ObjectRecord[];
  obstacles?: ObjectRecord[];
  reportingPoints?: ObjectRecord[];
  onMapClick?: (lat: number, lon: number) => void;
  clickedPoint?: { lat: number; lon: number } | null;
}

export default function WorldMap({ airspaces = [], layers, airports, navaids, obstacles, reportingPoints, onMapClick, clickedPoint }: WorldMapProps) {
  const tMap = useTranslations('map');
  const { waypoints, moveWaypoint, legs, setDeparture, setDestination, addEnroute } = useRoute();
  const [center, setCenter] = useState<[number, number] | null>(null);
  const [mapMode, setMapMode] = useState<'street' | 'satellite'>('street');
  const [showLocationError, setShowLocationError] = useState(false);
  const [navlogEntries, setNavlogEntries] = useState<NavlogEntry[]>([]);
  const [selectedPoint, setSelectedPoint] = useState<SelectedPoint | null>(null);
  const popupRef = useRef<HTMLDivElement | null>(null);
  const beakRef = useRef<HTMLDivElement | null>(null);
  const mapRef = useRef<L.Map>(null);

  const handleMarkerClick = useCallback((e: L.LeafletMouseEvent, data: ObjectRecord, kind: SelectedPoint['kind']) => {
    L.DomEvent.stopPropagation(e);
    setSelectedPoint({ lat: e.latlng.lat, lon: e.latlng.lng, data, kind });
  }, []);

  const closePopup = useCallback(() => setSelectedPoint(null), []);

  const kindToWpType = useCallback((kind: SelectedPoint['kind']): Waypoint['type'] => {
    if (kind === 'obstacle') return 'custom';
    return kind;
  }, []);

  const handleAdep = useCallback(
    (p: SelectedPoint) => {
      setDeparture({ name: p.data.name ?? p.data.icaoCode ?? 'ADEP', lat: p.lat, lon: p.lon, elev: p.data.elevation, type: kindToWpType(p.kind) });
      setSelectedPoint(null);
    },
    [setDeparture, kindToWpType],
  );

  const handleAdes = useCallback(
    (p: SelectedPoint) => {
      setDestination({ name: p.data.name ?? p.data.icaoCode ?? 'ADES', lat: p.lat, lon: p.lon, elev: p.data.elevation, type: kindToWpType(p.kind) });
      setSelectedPoint(null);
    },
    [setDestination, kindToWpType],
  );

  const handleWpt = useCallback(
    (p: SelectedPoint) => {
      addEnroute({ name: p.data.name ?? p.data.icaoCode ?? 'WPT', lat: p.lat, lon: p.lon, elev: p.data.elevation, type: kindToWpType(p.kind) });
      setSelectedPoint(null);
    },
    [addEnroute, kindToWpType],
  );

  // Compute navlog for leg coloring
  useEffect(() => {
    if (waypoints.length < 2) {
      setNavlogEntries([]);
      return;
    }
    const compute = async () => {
      const profile = await getTerrainProfile(waypoints);
      const entries = computeNavlog(legs, profile, 3500, airspaces as any);
      setNavlogEntries(entries);
    };
    compute();
  }, [waypoints, legs, airspaces]);

  const handleLocationClick = useCallback(() => {
    if (!('geolocation' in navigator)) {
      setShowLocationError(true);
      return;
    }
    navigator.geolocation.getCurrentPosition(
      pos => {
        const c: [number, number] = [pos.coords.latitude, pos.coords.longitude];
        setCenter(c);
        mapRef.current?.flyTo(c, 13, { duration: 1.5 });
      },
      () => setShowLocationError(true),
      { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 },
    );
  }, []);

  const handleMapClick = useCallback(
    (lat: number, lon: number) => {
      onMapClick?.(lat, lon);
    },
    [onMapClick],
  );

  const mapLayerUrl =
    mapMode === 'street'
      ? 'https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png'
      : 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}';
  const mapAttribution = mapMode === 'street' ? '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors' : 'Tiles &copy; Esri';

  const airportIcon = useMemo(() => createObjectIcon('airport'), []);
  const navaidIcon = useMemo(() => createObjectIcon('navaid'), []);
  const obstacleIcon = useMemo(() => createObjectIcon('obstacle'), []);
  const reportingPointIcon = useMemo(() => createObjectIcon('reporting-point'), []);

  return (
    <div className='h-full w-full isolate z-0 bg-slate-100 dark:bg-zinc-900 overflow-hidden relative'>
      <MapContainer center={DEFAULT_CENTER} zoom={DEFAULT_ZOOM} scrollWheelZoom className='h-full w-full z-0' zoomControl={false} ref={mapRef}>
        <TileLayer attribution={mapAttribution} url={mapLayerUrl} />

        {/* Terrain overlay */}
        {layers?.showTerrain &&
          TERRAIN_TILES.map(tile => <ImageOverlay key={tile.key} url={`/terrain/${tile.key}.png`} bounds={tile.bounds} opacity={layers.terrainOpacity} />)}

        {/* Airspace layers */}
        {airspaces.map((as, i) => {
          if (!as.geometry) return null;
          const geoJsonData = { type: 'Feature' as const, properties: { name: as.name, type: as.type }, geometry: as.geometry };
          const color = getAirspaceColor(as.type);

          const lowerStr =
            as.lowerLimit != null
              ? as.lowerLimit === 0
                ? 'GND'
                : as.lowerLimit <= 6500
                  ? `A${Math.round(as.lowerLimit / 100)}`
                  : `FL${String(Math.round(as.lowerLimit / 100)).padStart(3, '0')}`
              : '—';
          const upperStr =
            as.upperLimit != null
              ? as.upperLimit >= 66000
                ? 'UNL'
                : as.upperLimit <= 6500
                  ? `A${Math.round(as.upperLimit / 100)}`
                  : `FL${String(Math.round(as.upperLimit / 100)).padStart(3, '0')}`
              : '—';

          const typeLabels: Record<number, string> = {
            1: 'R',
            2: 'D',
            3: 'P',
            4: 'CTR',
            5: 'TMZ',
            6: 'RMZ',
            7: 'TMA',
            8: 'TRA',
            9: 'TSA',
            13: 'ATZ',
            18: 'BVLOS',
            21: 'LFA',
            28: 'SPORT',
            30: 'MRT',
            33: 'NPZ',
          };
          const typeLabel = typeLabels[as.type] ?? `Type ${as.type}`;

          return (
            <GeoJSON
              key={`as-${i}-${as.name}`}
              data={geoJsonData as any}
              style={{ color, weight: 1.5, opacity: 0.8, fillColor: color, fillOpacity: 0.1 }}
              onEachFeature={(_, layer) => {
                layer.bindPopup(
                  `<div style="font-family:sans-serif;font-size:12px;min-width:160px">
                    <div style="font-weight:700;margin-bottom:4px">${as.name}</div>
                    <div style="display:flex;gap:6px;align-items:center;margin-bottom:6px">
                      <span style="background:${color};color:#fff;border-radius:4px;padding:1px 6px;font-size:10px;font-weight:600">${typeLabel}</span>
                    </div>
                    <table style="width:100%;border-collapse:collapse;font-size:11px">
                      <tr><td style="color:#6b7280;padding:1px 4px 1px 0">↓ Lower</td><td style="font-weight:600">${lowerStr}</td></tr>
                      <tr><td style="color:#6b7280;padding:1px 4px 1px 0">↑ Upper</td><td style="font-weight:600">${upperStr}</td></tr>
                    </table>
                  </div>`,
                  { className: 'leaflet-popup-airspace' },
                );
              }}
            />
          );
        })}

        {/* Per-leg colored polylines */}
        {legs.map((leg, i) => {
          const entry = navlogEntries[i];
          const color = entry ? LEG_COLORS[entry.warningLevel] : '#3b82f6';
          return (
            <Polyline
              key={`leg-${i}`}
              positions={[
                [leg.from.lat, leg.from.lon],
                [leg.to.lat, leg.to.lon],
              ]}
              pathOptions={{ color, weight: 3, opacity: 0.9 }}
            />
          );
        })}

        {/* Leg info boxes at midpoints */}
        {navlogEntries.map(entry => {
          const leg = legs[entry.legIndex];
          if (!leg) return null;
          const midLat = (leg.from.lat + leg.to.lat) / 2;
          const midLon = (leg.from.lon + leg.to.lon) / 2;
          return (
            <Marker
              key={`info-${entry.legIndex}`}
              position={[midLat, midLon]}
              icon={createLegInfoIcon(entry.magneticTrack, entry.distanceNM, entry.warningLevel)}
              interactive={false}
            />
          );
        })}

        {/* Waypoint markers */}
        {waypoints.map((wp, i) => (
          <Marker
            key={wp.id}
            position={[wp.lat, wp.lon]}
            icon={createWaypointIcon(i, wp.role)}
            draggable
            eventHandlers={{
              dragend: e => {
                const { lat, lng } = e.target.getLatLng();
                moveWaypoint(i, lat, lng);
              },
            }}
          >
            <Popup className='text-xs'>
              <div className='flex flex-col gap-0.5'>
                <span className='font-semibold'>{wp.name}</span>
                <span className='text-slate-500'>
                  {wp.lat.toFixed(4)}°, {wp.lon.toFixed(4)}°
                </span>
                {wp.elev != null && <span className='text-slate-500'>{wp.elev} ft</span>}
              </div>
            </Popup>
          </Marker>
        ))}

        {/* Airport markers */}
        {airports?.map((a, i) => (
          <Marker key={`apt-${i}`} position={[a.lat, a.lon]} icon={airportIcon} eventHandlers={{ click: e => handleMarkerClick(e as any, a, 'airport') }} />
        ))}

        {/* Navaid markers */}
        {navaids?.map((n, i) => (
          <Marker key={`nav-${i}`} position={[n.lat, n.lon]} icon={navaidIcon} eventHandlers={{ click: e => handleMarkerClick(e as any, n, 'navaid') }} />
        ))}

        {/* Obstacle markers */}
        {obstacles?.map((o, i) => (
          <Marker key={`obs-${i}`} position={[o.lat, o.lon]} icon={obstacleIcon} eventHandlers={{ click: e => handleMarkerClick(e as any, o, 'obstacle') }} />
        ))}

        {/* Reporting point / VFR markers */}
        {reportingPoints?.map((rp, i) => (
          <Marker
            key={`rp-${i}`}
            position={[rp.lat, rp.lon]}
            icon={reportingPointIcon}
            eventHandlers={{ click: e => handleMarkerClick(e as any, rp, 'reporting-point') }}
          />
        ))}

        {/* Clicked point marker */}
        {clickedPoint && (
          <Marker
            position={[clickedPoint.lat, clickedPoint.lon]}
            icon={L.divIcon({
              className: '',
              html: `<div style="filter:drop-shadow(0 2px 4px rgba(0,0,0,0.3));">${renderToStaticMarkup(
                <Crosshair width={24} height={24} stroke='#0ea5e9' strokeWidth={2} fill='none' />,
              )}</div>`,
              iconSize: [24, 24],
              iconAnchor: [12, 12],
            })}
            interactive={false}
          />
        )}

        <UserLocationUpdater center={center} />
        <MapClickHandler onMapClick={handleMapClick} onClosePopup={closePopup} />
        {selectedPoint && <DomPopupTracker latLon={[selectedPoint.lat, selectedPoint.lon]} popupRef={popupRef} beakRef={beakRef} />}
      </MapContainer>

      {/* Map Controls */}
      <div className='absolute bottom-6 right-4 z-400 flex flex-col gap-2'>
        <button
          onClick={() => setMapMode(mapMode === 'street' ? 'satellite' : 'street')}
          className='flex h-12 w-12 items-center justify-center rounded-2xl bg-white/90 dark:bg-zinc-900/90 backdrop-blur-md shadow-lg border border-slate-200/80 dark:border-zinc-800/80 text-slate-700 dark:text-zinc-300 hover:bg-slate-50 dark:hover:bg-zinc-800 transition-colors'
          title={tMap('toggleLayer')}
          aria-label={tMap('toggleLayer')}
        >
          {mapMode === 'street' ? <Globe className='h-6 w-6' /> : <Map className='h-6 w-6' />}
        </button>
        <button
          onClick={handleLocationClick}
          className='flex h-12 w-12 items-center justify-center rounded-2xl bg-white/90 dark:bg-zinc-900/90 backdrop-blur-md shadow-lg border border-slate-200/80 dark:border-zinc-800/80 text-slate-700 dark:text-zinc-300 hover:bg-slate-50 dark:hover:bg-zinc-800 transition-colors'
          title={tMap('myLocation')}
          aria-label={tMap('myLocation')}
        >
          <LocateFixed className='h-6 w-6' />
        </button>
      </div>

      {selectedPoint && (
        <PointPopup
          point={selectedPoint}
          popupRef={popupRef}
          beakRef={beakRef}
          onClose={closePopup}
          onAdep={handleAdep}
          onAdes={handleAdes}
          onWpt={handleWpt}
        />
      )}

      {/* Location Error Modal */}
      {showLocationError && (
        <div className='absolute inset-0 z-500 flex items-center justify-center bg-black/50 backdrop-blur-sm px-4'>
          <div className='w-full max-w-sm rounded-2xl bg-white dark:bg-zinc-900 p-6 shadow-2xl'>
            <div className='mx-auto flex h-12 w-12 items-center justify-center rounded-full bg-red-100 dark:bg-red-500/20 mb-4'>
              <LocateFixed className='h-6 w-6 text-red-600 dark:text-red-400' />
            </div>
            <h3 className='text-center text-lg font-semibold text-slate-900 dark:text-zinc-100 mb-2'>{tMap('locationErrorTitle')}</h3>
            <p className='text-center text-sm text-slate-500 dark:text-zinc-400 mb-6'>{tMap('locationErrorMsg')}</p>
            <button
              onClick={() => setShowLocationError(false)}
              className='w-full rounded-xl bg-slate-900 dark:bg-zinc-100 px-4 py-2.5 text-sm font-medium text-white dark:text-zinc-900 hover:bg-slate-800 dark:hover:bg-zinc-200 transition-colors'
            >
              {tMap('close')}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback, useRef } from 'react';
import {
  db,
  type AirportRecord,
  type AirspaceRecord,
  type NavaidRecord,
  type ObstacleRecord,
  type ReportingPointRecord,
  type LocationRecord,
  type PeakRecord,
} from '@/lib/dexie/db';

interface AeroData {
  airports: AirportRecord[];
  airspaces: AirspaceRecord[];
  navaids: NavaidRecord[];
  obstacles: ObstacleRecord[];
  reportingPoints: ReportingPointRecord[];
}

interface AeroDataState {
  isOffline: boolean;
  hasOfflineData: boolean;
  lastDownloadDate: Date | null;
  isDownloading: boolean;
  isLoading: boolean;
  data: AeroData | null;
}

const DEFAULT_AGL_FT = 1000;

let cachedOnlineData: AeroData | null = null;

async function fetchOnlineData(): Promise<AeroData> {
  if (cachedOnlineData) return cachedOnlineData;

  const res = await fetch('/api/aero-data');
  if (!res.ok) throw new Error('Failed to fetch aero data');

  const data = await res.json();
  cachedOnlineData = data;
  return data;
}

async function getOfflineAeroData(): Promise<AeroData | null> {
  const meta = await db.syncMeta.get('main');
  if (!meta) return null;

  const [airports, airspaces, navaids, obstacles, reportingPoints] = await Promise.all([
    db.airports.toArray(),
    db.airspaces.toArray(),
    db.navaids.toArray(),
    db.obstacles.toArray(),
    db.reportingPoints.toArray(),
  ]);

  return { airports, airspaces, navaids, obstacles, reportingPoints };
}

export function useAeroData() {
  const [state, setState] = useState<AeroDataState>({
    isOffline: false,
    hasOfflineData: false,
    lastDownloadDate: null,
    isDownloading: false,
    isLoading: true,
    data: null,
  });

  const initializedRef = useRef(false);

  useEffect(() => {
    if (initializedRef.current) return;
    initializedRef.current = true;

    const init = async () => {
      const meta = await db.syncMeta.get('main');
      const hasOffline = !!meta;
      const online = navigator.onLine;

      try {
        if (online) {
          const data = await fetchOnlineData();
          setState(prev => ({
            ...prev,
            isOffline: false,
            hasOfflineData: hasOffline,
            lastDownloadDate: meta?.lastDownload ?? null,
            isLoading: false,
            data,
          }));
        } else if (hasOffline) {
          const data = await getOfflineAeroData();
          setState(prev => ({
            ...prev,
            isOffline: true,
            hasOfflineData: true,
            lastDownloadDate: meta?.lastDownload ?? null,
            isLoading: false,
            data,
          }));
        } else {
          setState(prev => ({
            ...prev,
            isOffline: true,
            hasOfflineData: false,
            isLoading: false,
          }));
        }
      } catch {
        if (hasOffline) {
          const data = await getOfflineAeroData();
          setState(prev => ({
            ...prev,
            isOffline: true,
            hasOfflineData: true,
            lastDownloadDate: meta?.lastDownload ?? null,
            isLoading: false,
            data,
          }));
        } else {
          setState(prev => ({ ...prev, isLoading: false, isOffline: true }));
        }
      }
    };

    init();
  }, []);

  useEffect(() => {
    const goOffline = () => setState(prev => ({ ...prev, isOffline: true }));
    const goOnline = () => {
      setState(prev => ({ ...prev, isOffline: false }));
      cachedOnlineData = null;
      fetchOnlineData()
        .then(data => setState(prev => ({ ...prev, data })))
        .catch(() => {});
    };

    window.addEventListener('offline', goOffline);
    window.addEventListener('online', goOnline);
    return () => {
      window.removeEventListener('offline', goOffline);
      window.removeEventListener('online', goOnline);
    };
  }, []);

  const downloadForOffline = useCallback(async () => {
    setState(prev => ({ ...prev, isDownloading: true }));

    try {
      const [aeroData, locationsRes, peaksRes] = await Promise.all([fetchOnlineData(), fetch('/data/locations.json'), fetch('/data/peaks.geojson')]);

      const locations: { n: string; lat: number; lon: number; elev: number }[] = await locationsRes.json();
      const peaksGeoJson = await peaksRes.json();

      const locationRecords: LocationRecord[] = locations.map(l => ({
        ...l,
        agl: DEFAULT_AGL_FT,
      }));

      const peakRecords: PeakRecord[] = peaksGeoJson.features
        .filter((f: any) => f.properties?.name)
        .map((f: any) => ({
          id: f.id || `peak-${f.geometry.coordinates[0]}-${f.geometry.coordinates[1]}`,
          name: f.properties.name,
          lon: f.geometry.coordinates[0],
          lat: f.geometry.coordinates[1],
          ele: parseFloat(f.properties.ele || '0'),
        }));

      await db.transaction('rw', [db.airports, db.airspaces, db.navaids, db.obstacles, db.reportingPoints, db.locations, db.peaks, db.syncMeta], async () => {
        await Promise.all([
          db.airports.clear(),
          db.airspaces.clear(),
          db.navaids.clear(),
          db.obstacles.clear(),
          db.reportingPoints.clear(),
          db.locations.clear(),
          db.peaks.clear(),
        ]);

        await Promise.all([
          db.airports.bulkAdd(
            aeroData.airports.map(({ openaipId, name, icaoCode, type, lat, lon, elevation, elevationUnit, geometry, trafficType, ppr, private: isPrivate, skydiveActivity, winchOnly, runways, frequencies }: any) => ({
              openaipId,
              name,
              icaoCode,
              type,
              lat,
              lon,
              elevation,
              elevationUnit,
              geometry,
              trafficType,
              ppr,
              private: isPrivate,
              skydiveActivity,
              winchOnly,
              runways,
              frequencies,
            }))
          ),
          db.airspaces.bulkAdd(
            aeroData.airspaces.map(({ openaipId, name, type, icaoClass, upperLimit, lowerLimit, geometry }: any) => ({
              openaipId,
              name,
              type,
              icaoClass,
              upperLimit,
              lowerLimit,
              geometry,
            }))
          ),
          db.navaids.bulkAdd(
            aeroData.navaids.map(({ openaipId, name, identifier, type, frequency, frequencyUnit, channel, range, rangeUnit, lat, lon, elevation, elevationUnit, sourceUpdatedAt }: any) => ({
              openaipId,
              name,
              identifier,
              type,
              frequency,
              frequencyUnit,
              channel,
              range,
              rangeUnit,
              lat,
              lon,
              elevation,
              elevationUnit,
              sourceUpdatedAt,
            }))
          ),
          db.obstacles.bulkAdd(
            aeroData.obstacles.map(({ openaipId, type, lat, lon, elevation, heightAgl }: any) => ({
              openaipId,
              type,
              lat,
              lon,
              elevation,
              heightAgl,
            }))
          ),
          db.reportingPoints.bulkAdd(
            aeroData.reportingPoints.map(({ openaipId, name, type, lat, lon, elevation }: any) => ({
              openaipId,
              name,
              type,
              lat,
              lon,
              elevation,
            }))
          ),
          db.locations.bulkAdd(locationRecords),
          db.peaks.bulkAdd(peakRecords),
        ]);

        await db.syncMeta.put({ id: 'main', lastDownload: new Date() });
      });

      setState(prev => ({
        ...prev,
        isDownloading: false,
        hasOfflineData: true,
        lastDownloadDate: new Date(),
      }));
    } catch (err) {
      console.error('Download for offline failed:', err);
      setState(prev => ({ ...prev, isDownloading: false }));
      throw err;
    }
  }, []);

  const searchWaypoints = useCallback(
    async (query: string) => {
      if (!query || query.length < 2) return [];

      const upperQuery = query.toUpperCase();
      const lowerQuery = query.toLowerCase();

      const source = state.isOffline && state.hasOfflineData ? 'offline' : 'online';

      if (source === 'offline') {
        const [airports, navaids, reportingPoints, locations, peaks] = await Promise.all([
          db.airports
            .filter(a => a.name.toLowerCase().includes(lowerQuery) || (a.icaoCode?.toUpperCase().includes(upperQuery) ?? false))
            .limit(10)
            .toArray(),
          db.navaids
            .filter(n => n.name.toLowerCase().includes(lowerQuery))
            .limit(10)
            .toArray(),
          db.reportingPoints
            .filter(rp => rp.name.toLowerCase().includes(lowerQuery))
            .limit(10)
            .toArray(),
          db.locations
            .filter(l => l.n.toLowerCase().includes(lowerQuery))
            .limit(10)
            .toArray(),
          db.peaks
            .filter(p => p.name.toLowerCase().includes(lowerQuery))
            .limit(10)
            .toArray(),
        ]);

        return [
          ...airports.map(a => ({ type: 'airport' as const, name: a.name, icao: a.icaoCode, lat: a.lat, lon: a.lon, elev: a.elevation })),
          ...navaids.map(n => ({ type: 'navaid' as const, name: n.name, lat: n.lat, lon: n.lon, elev: n.elevation })),
          ...reportingPoints.map(rp => ({ type: 'reporting-point' as const, name: rp.name, lat: rp.lat, lon: rp.lon, elev: rp.elevation })),
          ...locations.map(l => ({ type: 'location' as const, name: l.n, lat: l.lat, lon: l.lon, elev: l.elev })),
          ...peaks.map(p => ({ type: 'peak' as const, name: p.name, lat: p.lat, lon: p.lon, elev: p.ele })),
        ];
      }

      if (!state.data) return [];

      const airports = state.data.airports
        .filter(a => a.name.toLowerCase().includes(lowerQuery) || (a.icaoCode?.toUpperCase().includes(upperQuery) ?? false))
        .slice(0, 10);
      const navaids = state.data.navaids.filter(n => n.name.toLowerCase().includes(lowerQuery)).slice(0, 10);
      const reportingPoints = state.data.reportingPoints.filter(rp => rp.name.toLowerCase().includes(lowerQuery)).slice(0, 10);

      return [
        ...airports.map(a => ({ type: 'airport' as const, name: a.name, icao: a.icaoCode, lat: a.lat, lon: a.lon, elev: a.elevation })),
        ...navaids.map(n => ({ type: 'navaid' as const, name: n.name, lat: n.lat, lon: n.lon, elev: n.elevation })),
        ...reportingPoints.map(rp => ({ type: 'reporting-point' as const, name: rp.name, lat: rp.lat, lon: rp.lon, elev: rp.elevation })),
      ];
    },
    [state.isOffline, state.hasOfflineData, state.data]
  );

  const searchNearby = useCallback(
    async (lat: number, lon: number, radiusNM = 10) => {
      const radiusM = radiusNM * 1852;
      const origin = { latitude: lat, longitude: lon };

      const { getDistance: getDist, getRhumbLineBearing: getBearing } = await import('geolib');

      function withinRadius<T extends { lat: number; lon: number }>(items: T[]) {
        return items
          .map(item => {
            const dist = getDist(origin, { latitude: item.lat, longitude: item.lon });
            if (dist > radiusM) return null;
            const bearing = getBearing(origin, { latitude: item.lat, longitude: item.lon });
            return { ...item, distanceNM: dist / 1852, bearing: bearing < 0 ? bearing + 360 : bearing };
          })
          .filter(Boolean) as (T & { distanceNM: number; bearing: number })[];
      }

      const source = state.isOffline && state.hasOfflineData ? 'offline' : 'online';

      if (source === 'offline') {
        const [airports, navaids, locations, peaks] = await Promise.all([
          db.airports.toArray(),
          db.navaids.toArray(),
          db.locations.toArray(),
          db.peaks.toArray(),
        ]);

        const nearAirports = withinRadius(airports.map(a => ({ ...a, lat: a.lat, lon: a.lon })));
        const nearNavaids = withinRadius(navaids.map(n => ({ ...n, lat: n.lat, lon: n.lon })));
        const nearLocations = withinRadius(locations.map(l => ({ n: l.n, lat: l.lat, lon: l.lon, elev: l.elev })));
        const nearPeaks = withinRadius(peaks.map(p => ({ name: p.name, lat: p.lat, lon: p.lon, ele: p.ele })));

        const results: NearbySearchResult[] = [
          ...nearAirports.map(a => ({
            type: 'airport' as const,
            name: a.name,
            icao: (a as any).icaoCode,
            lat: a.lat,
            lon: a.lon,
            elev: (a as any).elevation,
            distanceNM: a.distanceNM,
            bearing: a.bearing,
          })),
          ...nearNavaids.map(n => ({
            type: 'navaid' as const,
            name: n.name,
            lat: n.lat,
            lon: n.lon,
            elev: (n as any).elevation,
            distanceNM: n.distanceNM,
            bearing: n.bearing,
          })),
          ...nearLocations.map(l => ({
            type: 'location' as const,
            name: (l as any).n,
            lat: l.lat,
            lon: l.lon,
            elev: (l as any).elev,
            distanceNM: l.distanceNM,
            bearing: l.bearing,
          })),
          ...nearPeaks.map(p => ({
            type: 'peak' as const,
            name: (p as any).name,
            lat: p.lat,
            lon: p.lon,
            elev: (p as any).ele,
            distanceNM: p.distanceNM,
            bearing: p.bearing,
          })),
        ];
        return results.sort((a, b) => a.distanceNM - b.distanceNM);
      }

      if (!state.data) return [];

      const allAirports = state.data.airports.map(a => ({
        type: 'airport' as const,
        name: a.name,
        icao: a.icaoCode,
        lat: a.lat,
        lon: a.lon,
        elev: a.elevation,
      }));
      const allNavaids = state.data.navaids.map(n => ({ type: 'navaid' as const, name: n.name, lat: n.lat, lon: n.lon, elev: n.elevation }));
      const allReportingPoints = state.data.reportingPoints.map(rp => ({
        type: 'reporting-point' as const,
        name: rp.name,
        lat: rp.lat,
        lon: rp.lon,
        elev: rp.elevation,
      }));

      // Locations from static JSON (always available in browser)
      let allLocations: { type: 'location'; name: string; lat: number; lon: number; elev: number }[] = [];
      try {
        const locData: { n: string; lat: number; lon: number; elev: number }[] = await fetch('/data/locations.json').then(r => r.json());
        allLocations = locData.map(l => ({ type: 'location' as const, name: l.n, lat: l.lat, lon: l.lon, elev: l.elev }));
      } catch {
        /* ignore */
      }

      const nearA = withinRadius(allAirports);
      const nearN = withinRadius(allNavaids);
      const nearRP = withinRadius(allReportingPoints);
      const nearL = withinRadius(allLocations);

      const results: NearbySearchResult[] = [
        ...nearA.map(a => ({ ...a, distanceNM: a.distanceNM, bearing: a.bearing })),
        ...nearN.map(n => ({ ...n, distanceNM: n.distanceNM, bearing: n.bearing })),
        ...nearRP.map(r => ({ ...r, distanceNM: r.distanceNM, bearing: r.bearing })),
        ...nearL.map(l => ({ ...l, distanceNM: l.distanceNM, bearing: l.bearing })),
      ];
      return results.sort((a, b) => a.distanceNM - b.distanceNM);
    },
    [state.isOffline, state.hasOfflineData, state.data]
  );

  return {
    ...state,
    downloadForOffline,
    searchWaypoints,
    searchNearby,
  };
}

export type WaypointSearchResult = {
  type: 'airport' | 'navaid' | 'reporting-point' | 'location' | 'peak';
  name: string;
  icao?: string | null;
  lat: number;
  lon: number;
  elev?: number | null;
};

export type NearbySearchResult = WaypointSearchResult & {
  distanceNM: number;
  bearing: number;
};

import geomagnetism from 'geomagnetism';
import type { Leg } from '@/components/route/route-context';
import type { TerrainSample } from '@/lib/terrain';

const DEFAULT_AGL_FT = 1000;
const OBSTACLE_BUFFER_FT = 300;

export type WarningLevel = 'safe' | 'warning' | 'danger';

export interface NavlogEntry {
  legIndex: number;
  from: string;
  to: string;
  distanceNM: number;
  trueBearing: number;
  magneticTrack: number;
  maxTerrainFt: number;
  safeAltitudeFt: number;
  altitudeFt: number;
  isBelowSafe: boolean;
  warningLevel: WarningLevel;
  warnings: string[];
}

export function getMagneticDeclination(lat: number, lon: number): number {
  const model = geomagnetism.model();
  const info = model.point([lat, lon]);
  return info.decl;
}

interface AirspaceZone {
  name: string;
  type: number;
  geometry: any;
  upperLimit?: number;
  lowerLimit?: number;
}

function isPointInPolygon(lat: number, lon: number, polygon: number[][]): boolean {
  let inside = false;
  for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
    const xi = polygon[i][1],
      yi = polygon[i][0];
    const xj = polygon[j][1],
      yj = polygon[j][0];
    const intersect = yi > lon !== yj > lon && lat < ((xj - xi) * (lon - yi)) / (yj - yi) + xi;
    if (intersect) inside = !inside;
  }
  return inside;
}

function legIntersectsAirspace(from: { lat: number; lon: number }, to: { lat: number; lon: number }, airspace: AirspaceZone): boolean {
  if (!airspace.geometry) return false;

  const geom = airspace.geometry;
  const polygons: number[][][] = [];

  if (geom.type === 'Polygon') {
    polygons.push(geom.coordinates[0]);
  } else if (geom.type === 'MultiPolygon') {
    geom.coordinates.forEach((poly: number[][][]) => polygons.push(poly[0]));
  }

  // Sample 10 points along the leg
  for (let t = 0; t <= 1; t += 0.1) {
    const lat = from.lat + t * (to.lat - from.lat);
    const lon = from.lon + t * (to.lon - from.lon);
    for (const ring of polygons) {
      if (isPointInPolygon(lat, lon, ring)) return true;
    }
  }

  return false;
}

// Types 6=Restricted, 8=Danger, 10=Prohibited
const DANGER_TYPES = new Set([6, 8, 10]);
// Types 1=CTR, 2=TMA
const CONTROLLED_TYPES = new Set([1, 2]);

export function computeNavlog(
  legs: Leg[],
  terrainProfile: TerrainSample[],
  defaultAltitudeFt: number,
  airspaces: AirspaceZone[] = [],
  maxObstacleHeightFt = 0,
  samplesPerLeg = 100,
): NavlogEntry[] {
  return legs.map((leg, i) => {
    const midLat = (leg.from.lat + leg.to.lat) / 2;
    const midLon = (leg.from.lon + leg.to.lon) / 2;
    const declination = getMagneticDeclination(midLat, midLon);

    let magneticTrack = leg.trueBearing - declination;
    if (magneticTrack < 0) magneticTrack += 360;
    if (magneticTrack >= 360) magneticTrack -= 360;

    const start = i * (samplesPerLeg + 1);
    const end = start + samplesPerLeg + 1;
    const legSamples = terrainProfile.slice(start, end);
    const maxTerrainFt = legSamples.length > 0 ? Math.max(...legSamples.map(s => s.elevationFt)) : 0;

    const safeAltitudeFt = maxTerrainFt + DEFAULT_AGL_FT + Math.max(maxObstacleHeightFt, OBSTACLE_BUFFER_FT);
    const altitudeFt = leg.altitudeFt ?? defaultAltitudeFt;
    const isBelowSafe = altitudeFt < safeAltitudeFt;

    const warnings: string[] = [];
    let warningLevel: WarningLevel = 'safe';

    if (isBelowSafe) {
      warnings.push(`Below safe altitude (${safeAltitudeFt} ft)`);
      warningLevel = 'warning';
    }

    for (const as of airspaces) {
      if (legIntersectsAirspace(leg.from, leg.to, as)) {
        if (DANGER_TYPES.has(as.type)) {
          warnings.push(`Through ${as.name}`);
          warningLevel = 'danger';
        } else if (CONTROLLED_TYPES.has(as.type)) {
          warnings.push(`Through ${as.name}`);
          if (warningLevel !== 'danger') warningLevel = 'warning';
        }
      }
    }

    return {
      legIndex: i,
      from: leg.from.name,
      to: leg.to.name,
      distanceNM: Math.round(leg.distanceNM * 10) / 10,
      trueBearing: Math.round(leg.trueBearing),
      magneticTrack: Math.round(magneticTrack),
      maxTerrainFt: Math.round(maxTerrainFt),
      safeAltitudeFt: Math.round(safeAltitudeFt),
      altitudeFt,
      isBelowSafe,
      warningLevel,
      warnings,
    };
  });
}

'use server';

import { prisma } from '@/lib/prisma';
import { auth, unstable_update } from '@/lib/auth';
import { z } from 'zod';
import { randomBytes, createHash } from 'crypto';
import bcrypt from 'bcryptjs';
import { revalidatePath } from 'next/cache';

const profileSchema = z.object({
  firstName: z.string().min(2, 'First name must be at least 2 characters'),
  lastName: z.string().min(2, 'Last name must be at least 2 characters'),
  username: z.string().min(3, 'Username must be at least 3 characters'),
});

export async function updateProfile(formData: FormData) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return { success: false, error: 'Unauthorized' };
    }

    const data = {
      firstName: formData.get('firstName') as string,
      lastName: formData.get('lastName') as string,
      username: formData.get('username') as string,
    };

    const validatedFields = profileSchema.safeParse(data);
    if (!validatedFields.success) {
      return { success: false, error: validatedFields.error.issues[0].message };
    }

    // Check username uniqueness
    if (data.username !== session.user.username) {
      const existingUser = await prisma.user.findUnique({
        where: { username: data.username },
      });

      if (existingUser) {
        return { success: false, error: 'Username is already taken' };
      }
    }

    const updatedUser = await prisma.user.update({
      where: { id: session.user.id },
      data: {
        firstName: data.firstName,
        lastName: data.lastName,
        username: data.username,
      },
    });

    await unstable_update({
      user: {
        firstName: data.firstName,
        lastName: data.lastName,
        username: data.username,
      }
    });

    revalidatePath('/settings');
    return { success: true };
  } catch (error) {
    console.error('[Settings] Update Profile:', error);
    return { success: false, error: 'Failed to update profile' };
  }
}

export async function updatePassword(formData: FormData) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return { success: false, error: 'Unauthorized' };
    }

    const currentPassword = formData.get('currentPassword') as string;
    const newPassword = formData.get('newPassword') as string;
    const confirmPassword = formData.get('confirmPassword') as string;

    if (newPassword !== confirmPassword) {
      return { success: false, error: 'New passwords do not match' };
    }

    if (newPassword.length < 8) {
      return { success: false, error: 'Password must be at least 8 characters long' };
    }

    const user = await prisma.user.findUnique({
      where: { id: session.user.id },
    });

    if (!user || !user.password) {
      return { success: false, error: 'User not found or misconfigured' };
    }

    const isCorrect = await bcrypt.compare(currentPassword, user.password);
    if (!isCorrect) {
      return { success: false, error: 'Incorrect current password' };
    }

    const hashedPassword = await bcrypt.hash(newPassword, 12);

    await prisma.user.update({
      where: { id: user.id },
      data: { password: hashedPassword },
    });

    revalidatePath('/settings');
    return { success: true };
  } catch (error) {
    console.error('[Settings] Update Password:', error);
    return { success: false, error: 'Failed to update password' };
  }
}

export async function requestEmailChange(formData: FormData) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return { success: false, error: 'Unauthorized' };
    }

    const newEmail = formData.get('email') as string;
    const locale = formData.get('locale') as string || 'en';

    if (!newEmail || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(newEmail)) {
      return { success: false, error: 'Invalid email address' };
    }

    const dbUser = await prisma.user.findUnique({
      where: { id: session.user.id }
    });

    if (!dbUser) {
      return { success: false, error: 'User not found' };
    }

    if (newEmail === dbUser.email) {
      return { success: false, error: 'This is already your current email' };
    }

    // Check if new email is in use
    const existing = await prisma.user.findUnique({ where: { email: newEmail } });
    if (existing) {
      return { success: false, error: 'This email is already in use by another account' };
    }

    // 1. Rate Limiting Check (max 2 active requests per user in the last 1 hour)
    const recentRequests = await prisma.verificationToken.count({
      where: {
        identifier: { startsWith: `email-change:${session.user.id}:` },
        expires: { gt: new Date() }
      }
    });

    if (recentRequests >= 2) {
      return { success: false, error: 'Too many requests. Please try again later.' };
    }

    // 2. Generate token
    const token = randomBytes(32).toString('hex');
    const hashedToken = createHash('sha256').update(token).digest('hex');
    
    // Identifier convention: email-change:USER_ID:NEW_EMAIL
    // Note: We deliberately DO NOT delete old requests here, so they accumulate and serve as our rate-limit counter!
    const identifier = `email-change:${session.user.id}:${newEmail}`;

    // 3. Save new request (expires in 1h)
    await prisma.verificationToken.create({
      data: {
        identifier,
        token: hashedToken,
        expires: new Date(Date.now() + 60 * 60 * 1000), // 1 hour
      },
    });

    // 4. Send Email
    const { sendEmailChangeConfirmation } = await import('@/lib/emails');
    const verifyLink = `${process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000'}/settings/verify-email?token=${token}&id=${encodeURIComponent(identifier)}`;
    
    await sendEmailChangeConfirmation(newEmail, verifyLink, dbUser.firstName, locale);

    return { success: true };
  } catch (error) {
    console.error('[Settings] Request Email Change:', error);
    return { success: false, error: 'Failed to request email change' };
  }
}

export async function confirmEmailChange(token: string, identifier: string) {
  try {
    const hashedToken = createHash('sha256').update(token).digest('hex');

    const verificationToken = await prisma.verificationToken.findFirst({
      where: { identifier, token: hashedToken },
    });

    if (!verificationToken) {
      return { success: false, error: 'Invalid or expired magic link' };
    }

    if (verificationToken.expires < new Date()) {
      await prisma.verificationToken.deleteMany({ where: { identifier } });
      return { success: false, error: 'Token has expired' };
    }

    // Parse identifier: email-change:USER_ID:NEW_EMAIL
    const parts = identifier.split(':');
    if (parts.length !== 3 || parts[0] !== 'email-change') {
      return { success: false, error: 'Invalid token structure' };
    }
    
    const userId = parts[1];
    const newEmail = parts[2];

    const user = await prisma.user.findUnique({ where: { id: userId } });
    if (!user) {
      return { success: false, error: 'User no longer exists' };
    }

    // Check one last time if email was taken while waiting
    const emailTaken = await prisma.user.findUnique({ where: { email: newEmail } });
    if (emailTaken && emailTaken.id !== user.id) {
      return { success: false, error: 'Email was taken by another user' };
    }

    // Update email
    await prisma.user.update({
      where: { id: userId },
      data: { email: newEmail },
    });

    // Delete all used/leftover tokens for this specific user's email changes (clean up)
    await prisma.verificationToken.deleteMany({ 
      where: { identifier: { startsWith: `email-change:${userId}:` } } 
    });

    await unstable_update({
      user: {
        email: newEmail,
      }
    });

    revalidatePath('/settings');
    return { success: true, email: newEmail };
  } catch (error) {
    console.error('[Settings] Confirm Email Change:', error);
    return { success: false, error: 'Failed to verify email' };
  }
}

